import {on} from 'delegated-events'
import {reload} from '@github-ui/updatable-content'
import {remoteForm} from '@github-ui/remote-form'

on('click', '.js-code-scanning-apply-autofix-form .js-code-scanning-apply-autofix-submit', function (event) {
  const submitButton = event.currentTarget
  const form = submitButton.closest<HTMLFormElement>('.js-code-scanning-apply-autofix-form')!

  const commitTitleInput = form.querySelector<HTMLInputElement>('input[name=commit_title]')!
  const commitMessageInput = form.querySelector<HTMLTextAreaElement>('textarea[name=commit_message]')!
  let message = commitTitleInput.value.trim()
  if (message === '') {
    message = commitTitleInput.defaultValue
  }
  const commitMessage = commitMessageInput.value.trim()
  if (commitMessage !== '') {
    message = `${message}\n\n${commitMessage}\n`
  }
  commitTitleInput.disabled = true
  commitMessageInput.disabled = true

  const messageInput = document.createElement('input')
  messageInput.setAttribute('type', 'hidden')
  messageInput.setAttribute('name', 'message')
  messageInput.value = message
  form.appendChild(messageInput)
})

remoteForm('.js-code-scanning-apply-autofix-form', async function (form, wants) {
  const dropdown = form.closest<HTMLElement>('details')!
  const containerParent = form.closest<HTMLElement>('.js-code-scanning-apply-autofix-container')!
  const errorMessageContainer = containerParent.querySelector<HTMLElement>('.js-error-message-placeholder')!

  try {
    await wants.json()

    dropdown.remove()
    reload()
  } catch (error) {
    // @ts-expect-error catch blocks are bound to `unknown` so we need to validate the type before using it
    if (error.name !== 'QueryError') {
      // @ts-expect-error catch blocks are bound to `unknown` so we need to validate the type before using it
      const errorMessage = error.response.json && error.response.json.error
      const errorMessageElement = errorMessageContainer.querySelector<HTMLElement>('.js-error-message')!

      errorMessageContainer.hidden = false
      errorMessageElement.textContent = errorMessage

      dropdown.remove()
    }
  }
})

/**
 * This file contains codespace realted main window commands.
 *
 * To add another command, define a new subclass
 * These commands can be exported to other main-wiondow-commands files to be executed on different pages
 */
import {MainWindowCommand} from '../main-window-command'

type Elements = {
  codespacesForm: HTMLFormElement | null
  codespacesTab: HTMLButtonElement | null
  codeModal: HTMLDetailsElement | null
  newCodespacesButton: HTMLElement | null
}

export class OpenCodespace extends MainWindowCommand {
  override title = 'Open in new codespace'
  override icon = 'codespaces-color-fg-muted'
  override priority = 11

  override isApplicable() {
    const elements = this.fetchElements()
    return !!(elements.codeModal && elements.codespacesForm && elements.newCodespacesButton && elements.codespacesTab)
  }

  override run() {
    const {codeModal, codespacesTab, newCodespacesButton} = this.fetchElements()
    if (!(codeModal && codespacesTab && newCodespacesButton)) return

    codeModal.open = true
    codespacesTab.click()

    if (newCodespacesButton instanceof HTMLButtonElement) {
      newCodespacesButton.click()
    }
  }

  fetchElements(): Elements {
    const codespacesForm = document.querySelector<HTMLFormElement>('.js-create-codespaces-form-command')
    const codeModal = codespacesForm?.closest<HTMLDetailsElement>('details') || null
    const codespacesTab = codeModal?.querySelector<HTMLButtonElement>('[data-tab="cloud"]') || null
    const newCodespacesButton =
      codespacesForm?.querySelector<HTMLElement>('summary[role="button"], button[type="submit"]') || null

    return {
      codespacesForm,
      codeModal,
      codespacesTab,
      newCodespacesButton,
    }
  }
}

import {controller, target, targets} from '@github/catalyst'

@controller('codespace-zero-config')
class CodespaceZeroConfigElement extends HTMLElement {
  @target declare regionConfig: HTMLInputElement
  @target declare vscsTarget: HTMLSelectElement
  @target declare vscsTargetUrl: HTMLInputElement
  @targets declare locationConfigs: HTMLSelectElement[]

  @targets declare vscsTargets: HTMLInputElement[]
  @targets declare vscsTargetUrls: HTMLInputElement[]
  @targets declare locations: HTMLInputElement[]

  connectedCallback() {
    this.toggleLocationConfigs('production')
  }

  updateVscsTargets() {
    this.vscsTargetUrl.disabled = this.vscsTarget.value !== 'local'
    this.toggleLocationConfigs(this.vscsTarget.value)

    for (const vscsTargetElement of this.vscsTargets) {
      vscsTargetElement.value = this.vscsTarget.value
    }
  }

  updateVscsTargetUrls() {
    for (const vscsTargetUrlElement of this.vscsTargetUrls) {
      vscsTargetUrlElement.value = this.vscsTargetUrl.value
    }
  }

  updateLocations(event: Event) {
    const locationSelect = event.currentTarget as HTMLSelectElement
    this.setLocationValues(locationSelect.value)
  }

  setLocationValues(selectedLocation: string) {
    for (const locationSelect of this.locations) {
      locationSelect.value = selectedLocation
    }
  }

  toggleLocationConfigs(vscs_target: string) {
    for (const locationSelect of this.locationConfigs) {
      if (locationSelect.getAttribute('data-vscs-target') === vscs_target) {
        locationSelect.hidden = false
        const firstOption = locationSelect.querySelector('option') as HTMLOptionElement
        if (firstOption) {
          firstOption.selected = true
          this.setLocationValues(firstOption.value)
        }
      } else {
        locationSelect.hidden = true
      }
    }
  }
}

import {ready} from '@github-ui/document-ready'
import {setCookie} from '@github-ui/cookies'

export type ColorMode = 'light' | 'dark'
export type ColorModeWithAuto = ColorMode | 'auto'

/**
 * Set the OS preferred color mode on page load
 */
;(async () => {
  await ready
  setPreferredColorModeCookie()

  // update the cookie when OS preferred color mode changes
  if (window.matchMedia) {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')

    if (mediaQuery?.addEventListener) {
      mediaQuery.addEventListener('change', setPreferredColorModeCookie)
    } else {
      mediaQuery.addListener(setPreferredColorModeCookie)
    }
  }
})()

function setPreferredColorModeCookie() {
  setCookie('preferred_color_mode', getPreferredColorMode() as string)
}

export function getPreferredColorMode(): ColorMode | undefined {
  if (prefersColorScheme('dark')) {
    return 'dark'
  } else if (prefersColorScheme('light')) {
    return 'light'
  }

  return undefined
}

function prefersColorScheme(scheme: ColorMode): boolean {
  return window.matchMedia && window.matchMedia(`(prefers-color-scheme: ${scheme})`).matches
}

function getColorModeAttribute() {
  const rootEl = document.querySelector('html[data-color-mode]')
  if (!rootEl) return undefined
  return rootEl.getAttribute('data-color-mode')
}

/**
 * Set the `data-color-mode` attribute on the html element of the page.
 */
export function setClientMode(mode: ColorModeWithAuto) {
  const rootEl = document.querySelector('html[data-color-mode]')
  if (!rootEl) {
    // Color modes are not active on this page
    return
  }
  rootEl.setAttribute('data-color-mode', mode)
}

export function setClientTheme(theme: string, type: ColorMode) {
  const rootEl = document.querySelector('html[data-color-mode]')
  if (!rootEl) {
    // Color modes are not active on this page
    return
  }
  rootEl.setAttribute(`data-${type}-theme`, theme)
}

/**
 * Returns the user theme as defined by the `data-light-theme` or
 * `data-dark-theme` attribute.
 */
export function getClientTheme(type: ColorMode) {
  const rootEl = document.querySelector('html[data-color-mode]')
  if (!rootEl) {
    // Color modes are not active on this page
    return
  }
  return rootEl.getAttribute(`data-${type}-theme`)
}

/**
 * Provides a stable color mode. This does not delineate the theme, but rather the light vs dark modes.
 *
 * If you're after the theme, please use {@link getClientTheme}
 */
export function getColorMode(fallback: ColorMode = 'light') {
  const mode = getColorModeAttribute()
  return (mode === 'auto' ? getPreferredColorMode() : mode) ?? fallback
}

