function enrichMarkdownRenderer(el: HTMLElement) {
  const iframeParams = {
    color_mode: getColorMode(), // TODO: Should viewscreen support color themes?
  }

  // ==> setup some state

  const type = el.getAttribute('data-type')!
  const src = el.getAttribute('data-src')!
  const identifier = el.getAttribute('data-identity')!

  const target = el.getElementsByClassName('js-render-enrichment-target')[0] as HTMLElement

  const loadingHandle = el.getElementsByClassName('js-render-enrichment-loader')[0] as HTMLElement

  // => get the fallback, errors states correctly

  const detailsParent = target.closest('details')

  const fallbackHandle = document.createElement('div')
  fallbackHandle.classList.add('js-render-enrichment-fallback')
  el.appendChild(fallbackHandle)

  const fallbackContentNode = target.firstElementChild!
  fallbackHandle.appendChild(fallbackContentNode)

  const api: Api = {
    setLoading(state) {
      loadingHandle.hidden = !state
    },
    setError(state, template) {
      api.setLoading(false) // always remove loading state
      if (state === false) return false // we did not render an error state

      fallbackContentNode.classList.toggle('render-plaintext-hidden', !state)

      if (template) {
        render([template, fallbackContentNode], fallbackHandle)
        return true
      }

      return false
    },
  }

  nodeHandle.set(el, api)

  // ==> real constructor

  const plainText = target.getAttribute('data-plain')
  const contentJson = target.getAttribute('data-json')

  if (contentJson == null || plainText == null) {
    api.setError(true, html`<p class="flash flash-error">Unable to render rich display</p>`)
    throw new Error(`Expected to see input data for type: ${type}`)
  }

  const iframe = makeIframe(src, iframeParams, {
    type,
    identifier,
    contentJson,
  })

  const fullScreenIframe = makeIframe(src, iframeParams, {
    type,
    identifier: `${identifier}-fullscreen`,
    contentJson,
  })

  const buttons = makeEnhancedBlockActions(
    plainText,
    () => {
      // Beware hacks, we need to add the iframe to the nearest box body of the modal
      render(fullScreenIframe, target.getElementsByClassName('Box-body')[0]!)
    },
    {
      type,
    },
  )

  if (detailsParent && !detailsParent.open) {
    detailsParent.ontoggle = () => {
      if (detailsParent.open) {
        render([buttons, iframe], target)
        detailsParent.ontoggle = null
      }
    }
  } else {
    render([buttons, iframe], target)
  }
}

observe('.js-render-needs-enrichment', {
  constructor: HTMLElement,
  initialize: enrichMarkdownRenderer,
})

/**
 * Toggling back and forth between the `preview` and `write` tabs produces jank in
 * the form of an occasionally visible fully rendered chart. This is because we leave the
 * chart on the page until a request to regenerate the chart can be made.
 *
 * So, we add an event in `preview.ts` we can hook into,
 * and clear out the previously rendered chart before requesting a new one from viewscreen
 */
on('preview:toggle:off', '.js-previewable-comment-form', function (event) {
  const target = event.currentTarget
  const htmlEl = target.querySelector<HTMLElement>('.js-render-needs-enrichment')
  const enrichTarget = htmlEl?.querySelector('.js-render-enrichment-target')

  if (!enrichTarget) {
    return
  }

  enrichTarget.textContent = ''
})

on('preview:rendered', '.js-previewable-comment-form', function (event) {
  const target = event.currentTarget
  const htmlEl = target.querySelector<HTMLElement>('.js-render-needs-enrichment')
  if (htmlEl) {
    nodeHandle.get(htmlEl)?.setLoading(false)
  }
})

/**
 * This file contains main window commands that should appear everywhere. This
 * is useful when a command applies in many contexts. You can control when the
 * command is available to run by implementing `isApplicable`.
 *
 * To add another command, define a new subclass and append the
 * class to the default export at the bottom of the file.
 */
import {type ColorModeWithAuto, getClientTheme, setClientMode, setClientTheme} from '../../color-modes'
import {type CommandPalette, StaticItemsPage} from '@github-ui/command-palette-element'
import {MainWindowCommand, MainWindowGlobalCommand} from '../main-window-command'
import type {MainWindowCommandItem} from '../items/main-window-command-item'
import {SwitchTabSize} from './everywhere/switch-tab-size'
import {verifiedFetch} from '@github-ui/verified-fetch'

class OpenInDotDev extends MainWindowCommand {
  override title = 'Open in github.dev editor'
  override icon = 'codespaces-color-fg-muted'
  override priority = 10

  override isApplicable() {
    return this.fetchLink() instanceof HTMLAnchorElement
  }

  fetchLink() {
    return document.querySelector<HTMLAnchorElement>('.js-github-dev-shortcut')
  }

  override run() {
    this.fetchLink()?.click()
  }
}

export class SwitchTheme extends MainWindowGlobalCommand {
  override title = 'Switch theme'
  override icon = 'paintbrush-color-fg-muted'
  override priority = 9
  override dismissAfterRun = false

  override run(commandPalette: CommandPalette) {
    commandPalette.pushPage(new StaticItemsPage(this.title, 'switch-theme-page-1', this.pageItems), true)
  }

  get pageItems(): MainWindowCommandItem[] {
    return [SwitchToDark, SwitchToLight, SwitchToDarkDimmed, SwitchToDarkHighContrast, SwitchToAuto].map(command =>
      command.item(),
    )
  }

  override select(commandPalette: CommandPalette) {
    this.run(commandPalette)
  }
}

class SwitchToDark extends MainWindowCommand {
  override title = 'Default dark'
  override icon = 'moon-color-fg-muted'
  mode: ColorModeWithAuto = 'dark'
  theme = 'dark'
  override group = ''

  applyTheme() {
    this.loadStyles(this.theme)

    if (this.mode !== 'auto') {
      setClientTheme(this.theme, this.mode)
    }
    setClientMode(this.mode)
  }

  override async run() {
    // Set color theme in browser immediately to provide instantaneous response.
    this.applyTheme()
    this.saveSettings(this.mode, this.lightTheme, this.darkTheme)
  }

  /**
   * Save color mode settings to server. If successful, the server settings are
   * applied to the browser to ensure what the user sees is matches the server.
   */
  async saveSettings(colorMode: ColorModeWithAuto = this.mode, lightTheme?: string, darkTheme?: string) {
    const formData = new FormData()

    formData.set('color_mode', colorMode)
    if (lightTheme) formData.set('light_theme', lightTheme)
    if (darkTheme) formData.set('dark_theme', darkTheme)

    const response = await verifiedFetch('/settings/appearance/color_mode', {
      method: 'PUT',
      body: formData,
    })

    const settings = (await response.json()) as {
      color_mode: ColorModeWithAuto
      light_theme: string
      dark_theme: string
    }

    // Load theme CSS
    this.loadStyles(settings.light_theme)
    this.loadStyles(settings.dark_theme)

    // Set theme CSS classes
    setClientTheme(settings.light_theme, 'light')
    setClientTheme(settings.dark_theme, 'dark')

    // Set color mode classes
    setClientMode(settings.color_mode)
  }

  loadStyles(theme: string) {
    const linkTag = document.querySelector<HTMLLinkElement>(`link[data-color-theme='${theme}']`)

    if (linkTag && !linkTag.hasAttribute('href') && linkTag.hasAttribute('data-href')) {
      linkTag.setAttribute('href', linkTag.getAttribute('data-href')!)
    }
  }

  get darkTheme(): string | undefined {
    if (this.mode === 'dark') {
      return this.theme
    } else {
      return getClientTheme('dark')!
    }
  }

  get lightTheme(): string | undefined {
    if (this.mode === 'light') {
      return this.theme
    } else {
      return getClientTheme('light')!
    }
  }
}

class SwitchToDarkHighContrast extends SwitchToDark {
  override title = 'Switch theme to dark high contrast'
  override theme = 'dark_high_contrast'
}

class SwitchToDarkDimmed extends SwitchToDark {
  override title = 'Soft dark'
  override theme = 'dark_dimmed'
}

class SwitchToLight extends SwitchToDark {
  override title = 'Default light'
  override icon = 'sun-color-fg-muted'
  override mode: ColorModeWithAuto = 'light'
  override theme = 'light'
}

class SwitchToAuto extends SwitchToDark {
  override title = 'Sync with system settings'
  override icon = 'sun-color-fg-muted'
  override mode: ColorModeWithAuto = 'auto'

  override get darkTheme() {
    return undefined
  }

  override get lightTheme() {
    return undefined
  }
}

class UpdateSubscription extends MainWindowCommand {
  constructor() {
    super()
    const isSubscribeCommand = this.isSubscribe()
    this.title = `${isSubscribeCommand ? 'Subscribe' : 'Unsubscribe'}`
    this.icon = `${isSubscribeCommand ? 'bell' : 'bell-slash'}-color-fg-muted`
  }

  override isApplicable() {
    return this.fetchButton() instanceof HTMLButtonElement && this.fetchButton()?.disabled === false
  }

  isSubscribe() {
    return this.fetchButton()?.textContent?.trim() === 'Subscribe'
  }

  fetchButton() {
    return document.querySelector<HTMLButtonElement>('[data-thread-subscribe-button]')
  }

  override run() {
    this.fetchButton()?.click()
  }
}

export default [OpenInDotDev, SwitchTabSize, SwitchTheme, UpdateSubscription]

import {controller, target} from '@github/catalyst'
import {getBaseFetchHeaders} from '@github-ui/fetch-headers'

@controller('export-branch')
class ExportBranchElement extends HTMLElement {
  @target declare form: HTMLFormElement
  @target declare loadingIndicator: HTMLElement
  @target declare viewBranchLink: HTMLAnchorElement
  abortPoll: AbortController | null = null

  connectedCallback() {
    this.abortPoll = new AbortController()
    if (!this.loadingIndicator.hidden) {
      this.startPoll()
    }
  }

  disconnectedCallback(): void {
    this.abortPoll?.abort()
  }

  applyPublishParams() {
    const codespaceId = this.form.getAttribute('data-codespace-id')
    const publishForm = document.querySelector<HTMLFormElement>(
      `[data-codespace-id='${codespaceId}'][data-class="publish-codespace-form"]`,
    )
    if (publishForm) {
      const publishFormData = Object.fromEntries(new FormData(publishForm).entries())
      if (this.form) {
        const queryString = `?name=${publishFormData.name}&visibility=${publishFormData.visibility}`
        const updatedUrl = (this.form.getAttribute('action') || '').split('?')[0] + queryString
        this.form.setAttribute('action', updatedUrl)
      }
    }
  }

  async exportBranch(event: Event) {
    event.preventDefault()

    // Show the loading indicator immediately on click, which behaves more
    // like all the buttons throughout the app using data-disable-with.
    this.form.hidden = true
    this.loadingIndicator.hidden = false

    const response = await fetch(this.form.action, {
      method: this.form.method,
      body: new FormData(this.form),
      headers: {
        // We're passing *both* the Accept header and the XHR header. Ideally
        // we'd *only* pass Accept but currently the SAML filter only returns a
        // 401 for XHR requests. So we need to pass both headers to get the
        // behavior we want here.
        Accept: 'text/fragment+html',
        ...getBaseFetchHeaders(),
      },
    })

    if (response.ok) {
      this.startPoll()
    } else {
      this.form.hidden = false
      this.loadingIndicator.hidden = true
    }
  }

  private async startPoll() {
    const url = this.getAttribute('data-exported-codespace-url') || ''
    const response = await this.poll(url)
    if (response) {
      if (response.ok) {
        this.loadingIndicator.hidden = true
        this.viewBranchLink.hidden = false
      } else {
        const errorRedirectUrl = this.getAttribute('data-export-error-redirect-url') || ''
        window.location.href = encodeURI(errorRedirectUrl)
      }
    }
  }

  private async poll(url: string, wait = 1000): Promise<Response | undefined> {
    // The AbortController will be aborted if the component is disconnected (i.e. removed from the DOM)
    if (this.abortPoll?.signal.aborted) {
      return undefined
    }
    const response = await fetch(url, {signal: this.abortPoll?.signal})
    if (response.status === 202 || response.status === 404) {
      await new Promise(resolve => setTimeout(resolve, wait))
      return this.poll(url, wait * 1.5)
    }
    return response
  }
}

// Diff Expander
//
// Expand Diff hunk context lines.
//
// Types of expanders
//
// * Top hunk expander: On the first hunk line. Always expands upwards.
// * Middle hunk expander: In between hunks. Still expands upwards but has
//     previous and next lines.
// * Bottom expander: No hunk line. Expands downwards.
//

import {fire, on} from 'delegated-events'
import type {IncludeFragmentElement} from '@github/include-fragment-element'
import {scrollIntoView as _scrollIntoView} from '../sticky-scroll-into-view'
import {ensureExpanded} from '../behaviors/details'
import {fetchSafeDocumentFragment} from '@github-ui/fetch-utils'
import {findElementByFragmentName} from '../fragment-target'
import hashChange from '../behaviors/hash-change'
import {matchHash} from './helpers'
import {parseHTML} from '@github-ui/parse-html'
import {preservePosition} from 'scroll-anchoring'
import {collapseAllInContainer, expandAllInContainer, supportsRichExpanding} from '../behaviors/render-editor'

function loadDiff(entryContainer: Element): Promise<string> {
  const fragment = entryContainer.querySelector<IncludeFragmentElement>('.js-diff-entry-loader')!
  const placeholder = entryContainer.querySelector('.js-diff-placeholder')!
  const button = entryContainer.querySelector<HTMLButtonElement>('button.js-diff-load')!
  const buttonText = entryContainer.querySelector<HTMLElement>('.js-button-text')!

  // show loader and disable button
  placeholder.setAttribute('fill', "url('#animated-diff-gradient')")
  buttonText.textContent = button.getAttribute('data-disable-with') || ''
  button.disabled = true

  const url = new URL(fragment.getAttribute('data-fragment-url') || '', window.location.origin)
  fragment.src = url.toString()

  return fragment.data
}

function scrollIntoView(element: Element) {
  ensureExpanded(element)
  _scrollIntoView(element)
}

interface Expansion {
  anchor: string
  side: string
  line: string
  lastLine?: string
  hashFragment: string
  partialHashFragment: string
}

hashChange(function handleHashChange() {
  const expansion = parseExpansion(window.location.hash)
  if (!expansion) return

  // The line exists and no range was provided, so return early.
  if (findElementByFragmentName(document, expansion.hashFragment) && !expansion.lastLine) {
    return
  }

  findAndActivateExpander(expansion, 0)
})

function parseExpansion(hash?: string): Expansion | undefined {
  if (!hash) return

  const match = matchHash(hash)
  if (!match) return

  const anchor = match[1]!
  const side = match[2]!
  const line = match[3]!
  const lastLine = match[5]
  const hashFragment = anchor + side + line
  const partialHashFragment = anchor + side
  return {anchor, side, line, lastLine, hashFragment, partialHashFragment}
}

async function findAndActivateExpander(expansion: Expansion, retries: number) {
  const {anchor, side, line, lastLine, hashFragment, partialHashFragment} = expansion

  const file = findElementByFragmentName(document, anchor)
  if (!file) return

  const expanders = findExpanders(file, side, line, lastLine)
  // The range has no expanders, so the range may be fully loaded,
  // or it may be a progressive diff.
  if (!expanders.length) {
    const element = findElementByFragmentName(document, hashFragment)
    if (element) {
      scrollIntoView(element)
      return
    }

    // No element was found, so let's try to load the diff.
    const loader = file.querySelector('.js-diff-load-container')
    if (!loader) return
    try {
      await loadDiff(loader)
      const el = findElementByFragmentName(document, hashFragment)
      if (el instanceof HTMLElement) {
        scrollIntoView(el)
      }
    } catch {
      // An error occurred so scroll to the progressive diff.
      scrollIntoView(file)
    }

    return
  }

  await activateExpanders(expanders, partialHashFragment)

  const maxRetries = 1
  const element = findElementByFragmentName(document, hashFragment)
  const expanders2 = findExpanders(file, side, line, lastLine)
  if (expanders2.length) {
    // If a range was requested and there are more expanders, keep expanding.
    findAndActivateExpander(expansion, retries)
  } else if (element) {
    // Otherwise we've found the element to scroll to and expanded all its elements
    scrollIntoView(element)
  } else if (retries < maxRetries) {
    findAndActivateExpander(expansion, retries + 1)
  }
}

on('click', '.js-expand', function (event) {
  event.preventDefault()
  activateExpander(event.currentTarget as HTMLAnchorElement)
})

function activateExpanders(expanders: HTMLAnchorElement[], hashFragment: string): Promise<unknown> {
  return Promise.all(expanders.map(expander => activateExpander(expander, hashFragment)))
}

async function activateExpander(expander: HTMLAnchorElement, partialHashFragment?: string): Promise<void> {
  let anchor
  if (partialHashFragment) {
    const attrName = partialHashFragment.slice(-1) === 'R' ? 'data-right-range' : 'data-left-range'
    const range = expander.getAttribute(attrName) || ''
    const start = parseInt(range.split('-')[0]!, 10)
    anchor = partialHashFragment + start
  } else {
    anchor = expander.hash.slice(1)
  }

  const baseURL = expander.getAttribute('data-url')!
  const url = new URL(baseURL, window.location.origin)
  const params = new URLSearchParams(url.search.slice(1))
  params.append('anchor', anchor)
  url.search = params.toString()

  const data = await fetchSafeDocumentFragment(document, url.toString())

  const container = expander.closest<HTMLElement>('.js-file')
  if (!container) {
    return
  }

  const expandableLine = expander.closest<HTMLElement>('.js-expandable-line')!
  const nextLine = next(expandableLine, '.file-diff-line')
  if (nextLine) {
    preservePosition(nextLine, () => {
      expandableLine.replaceWith(data)
    })
  } else {
    expandableLine.replaceWith(data)
  }

  fire(container, 'expander:expanded')

  // Remove the expand-all button if there are no remaining
  // directional expanders
  removeExpandAllButton(container)
}

function next(el: Element, selector: string): HTMLElement | null {
  const sibling = el.nextElementSibling
  return sibling instanceof HTMLElement && sibling.matches(selector) ? sibling : null
}

// Find js-expand class that matches line number range.
//
// js-expand Elements are annotated with left and right ranges of line numbers
// they can expand to.
//
//   <a class="js-expand" data-left-range="8-21" data-right-range="9-20">
//
// Where "8-21" is an inclusive range.
//
//   findExpander(file, 'L', '20')
//
// container - .file Element
// side      - 'L' or 'R' String
// line      - Line number String
function findExpanders(
  container: Element,
  side: string,
  line: string,
  lastLine: string | undefined,
): HTMLAnchorElement[] {
  const lineNum = parseInt(line, 10)
  const lastLineNum = parseInt(lastLine || '', 10)
  return Array.from(container.querySelectorAll<HTMLAnchorElement>('.js-expand')).filter(el => {
    const attrName = side === 'R' ? 'data-right-range' : 'data-left-range'
    const range = (el.getAttribute(attrName) || '').split('-')
    const start = parseInt(range[0]!, 10)
    const end = parseInt(range[1]!, 10)
    if (start <= lineNum && lineNum <= end) {
      return true
    } else if (lineNum <= start && end <= lastLineNum) {
      return true
    } else if (start <= lastLineNum && lastLineNum <= end) {
      return true
    }
    return false
  })
}

interface ExpanderRange {
  left: {
    start: string
    end: string
    size: string
  }
  right: {
    start: string
    end: string
    size: string
  }
  position: string
}

interface DocumentFragments {
  content: DocumentFragment
  position: string
}

interface DocumentFragmentResponse {
  content: string
  position: string
}

function removeExpandAllButton(container: Element) {
  const expandFullWrapper = container.querySelector<HTMLButtonElement>('.js-expand-full-wrapper')
  if (!expandFullWrapper) return

  const expanders = Array.from(container.querySelectorAll<HTMLAnchorElement>('.js-expand'))
  if (expanders.length === 0) {
    expandFullWrapper.parentElement!.removeChild(expandFullWrapper)
  }
}

async function fetchManySafeDocumentFragments(document: Document, url: RequestInfo): Promise<DocumentFragments[]> {
  const response = await self.fetch(url, {
    headers: {'Content-Type': 'application/json', Accept: 'application/json'},
  })

  if (!response.ok) {
    throw new Error(`Request to blob_expand failed with status code ${response.status}`)
  }

  const fragments = (await response.json()) as DocumentFragmentResponse[]
  return fragments.map(fragment => ({
    ...fragment,
    content: parseHTML(document, fragment.content),
  }))
}

function maybeHandleRichExpanding(
  container: Element,
  action: typeof expandAllInContainer | typeof collapseAllInContainer,
) {
  if (container instanceof HTMLElement && supportsRichExpanding(container)) {
    return action(container)
  }
  return false
}

on('click', '.js-expand-full', async evt => {
  evt.preventDefault()
  const target = evt.currentTarget
  const container = target.closest('.file')!
  const baseURL = target.getAttribute('data-url')!
  const ranges = getAllHunkRanges(container)

  function expandUI() {
    // Remove the button now that we've expanded the full file
    target.setAttribute('hidden', 'true')

    // Show the collapse button
    const collapseBtn = container.querySelector('.js-collapse-diff')
    if (collapseBtn) collapseBtn.removeAttribute('hidden')

    // Ensure the file is "open"
    container.classList.add('open')
    container.classList.add('Details--on')
  }

  if (maybeHandleRichExpanding(container, expandAllInContainer)) return void expandUI()

  // If there are no ranges to fetch, we shouldn't bother. In this case, the UI
  // shouldn't have even rendered the button in the first place.
  if (ranges.length === 0) return

  const url = new URL(baseURL, window.location.origin)
  const params = new URLSearchParams(url.search.slice(1))

  for (const range of ranges) {
    params.append('ranges[]last_left', range.left.start)
    params.append('ranges[]left', range.left.end)
    params.append('ranges[]left_hunk_size', range.left.size)
    params.append('ranges[]last_right', range.right.start)
    params.append('ranges[]right', range.right.end)
    params.append('ranges[]right_hunk_size', range.right.size)

    // Attach the position of the relevant line, to replace the
    // right element after we've received the fragments
    params.append('ranges[]position', range.position)
  }

  url.search = params.toString()

  const fragments = await fetchManySafeDocumentFragments(document, url.toString())
  const expanders = [...container.querySelectorAll('.js-expand')]

  for (const {content, position} of fragments) {
    // Use the index of the original expander that we're replacing
    const index = parseInt(position, 10)
    const expander = expanders[index]
    if (!expander) return

    const expandableLine = expander.closest<HTMLElement>('.js-expandable-line')!
    const nextLine = next(expandableLine, '.file-diff-line')
    if (nextLine) {
      preservePosition(nextLine, () => {
        expandableLine.after(content)
      })
    } else {
      expandableLine.after(content)
    }

    // Hide the line in case we want to show it again after
    expandableLine.setAttribute('hidden', 'true')
  }

  expandUI()
})

on('click', '.js-collapse-diff', evt => {
  const target = evt.currentTarget
  const container = target.closest('.file')!

  function collapseUI() {
    // Show the expand button, hide this one
    target.setAttribute('hidden', 'true')
    const expandBtn = container.querySelector('.js-expand-full')
    if (expandBtn) expandBtn.removeAttribute('hidden')
  }

  if (maybeHandleRichExpanding(container, collapseAllInContainer)) return void collapseUI()

  // Remove all the expanded lines
  const expandedLines = [...container.querySelectorAll('.blob-expanded[data-expanded-full="true"]')]
  for (const el of expandedLines) {
    el.parentElement!.removeChild(el)
  }

  // Unhide the diff header lines that show expanders
  const expandableLines = [...container.querySelectorAll('.js-expandable-line')]
  for (const el of expandableLines) {
    el.removeAttribute('hidden')
  }

  collapseUI()
})

function getExpanderRange(expander: HTMLAnchorElement, index: number): ExpanderRange {
  const url = new URL(expander.getAttribute('data-url')!, window.location.origin)
  const params = url.searchParams

  return {
    // Store the index of this expander in the list of expanders within
    // this container. This will be used after the request is made, to
    // know which DOM elements to replace with the new `.blob-expanded` lines
    position: index.toString(),
    left: {
      start: params.get('last_left')!,
      end: params.get('left')!,
      size: params.get('left_hunk_size')!,
    },
    right: {
      start: params.get('last_right')!,
      end: params.get('right')!,
      size: params.get('right_hunk_size')!,
    },
  }
}

function getAllHunkRanges(container: Element): ExpanderRange[] {
  const expanders = Array.from(container.querySelectorAll<HTMLAnchorElement>('.js-expand'))
  const allRanges = expanders.map((el, index) => getExpanderRange(el, index))

  let skipNextRange = false
  const ranges: ExpanderRange[] = []
  for (let i = 0; i < allRanges.length; i++) {
    // This range should be skipped because its the same
    // as the previous range
    if (skipNextRange) {
      skipNextRange = false
      continue
    }

    const range = allRanges[i]!
    const nextRange = allRanges[i + 1]

    // See if these two are duplicates. This will happen when two expanders
    // are in the same containing div, and clicking either one would expand the
    // same range.
    skipNextRange =
      !!nextRange &&
      range.left.start === nextRange.left.start &&
      range.left.end === nextRange.left.end &&
      range.right.start === nextRange.right.start &&
      range.right.end === nextRange.right.end

    ranges.push(range)
  }

  return ranges
}

import safeStorage from '@github-ui/safe-storage'

const experimentsLocalStorageKey = 'blackbird_experiments'
const experimentsDebugScoringKey = 'blackbird_debug_scoring'

export function getBlackbirdExperiments(): string[] {
  const experiments = safeStorage('localStorage').getItem(experimentsLocalStorageKey)
  if (!experiments) return []

  return experiments.split(',')
}

export function setBlackbirdExperiments(experiments: string[]): void {
  safeStorage('localStorage').setItem(experimentsLocalStorageKey, experiments.join(','))
}

export function debugScoringInfoEnabled(): boolean {
  const enabled = safeStorage('localStorage').getItem(experimentsDebugScoringKey)
  return enabled !== null
}

export function setDebugScoringInfoEnabled(enabled: boolean): void {
  if (enabled) {
    safeStorage('localStorage').setItem(experimentsDebugScoringKey, '1')
  } else {
    safeStorage('localStorage').removeItem(experimentsDebugScoringKey)
  }
}

import {filterSort} from '@github-ui/filter-sort'
import {compare, fuzzyScore} from '@github-ui/fuzzy-filter'
import type {QueryEvent, SearchProvider, Octicon} from '@github-ui/query-builder-element/query-builder-api'
import {FetchDataEvent, SearchItem} from '@github-ui/query-builder-element/query-builder-api'
import type {QueryBuilderElement} from '@github-ui/query-builder-element'
import {isContentNode, isQualifier} from '../parsing/common'
import type {ParsedIntermediateRepresentation} from '../qbsearch-input-element'
import {ExplorePages, InitialExplorePages} from '../suggestions/explore-pages'

interface ExplorePage {
  title: string
  url: string
  octicon: Octicon | string
}

const resultsPriority = 11 // The priority of the explore search provider, higher numbers appear at the bottom of the results

export class ExploreProvider extends EventTarget implements SearchProvider {
  priority = resultsPriority
  name = 'Explore'
  singularItemName = 'explore page'
  value = 'explore'
  type = 'search' as const
  manuallyDetermineFilterEligibility = true

  #querySuggestions: ExplorePage[] | null = null
  #defaultSuggestions: ExplorePage[] | null = null

  queryBuilder: QueryBuilderElement

  constructor(queryBuilder: QueryBuilderElement) {
    super()
    this.queryBuilder = queryBuilder
    this.queryBuilder.addEventListener('query', this)
  }

  // For experimental / testing, we will get the explore pages from a hardcoded list from now.
  #fetchQuerySuggestions() {
    const data = Promise.resolve(ExplorePages)
    this.dispatchEvent(new FetchDataEvent(data))
    return data
  }

  #fetchDefaultSuggestions() {
    const data = Promise.resolve(InitialExplorePages)
    this.dispatchEvent(new FetchDataEvent(data))
    return data
  }

  async #addDefaultSuggestions() {
    this.#defaultSuggestions = await this.#fetchDefaultSuggestions()
    for (const page of this.#defaultSuggestions) {
      this.dispatchEvent(
        new SearchItem({
          value: page.title,
          icon: page.octicon as Octicon,
          priority: resultsPriority,
          scope: 'EXPLORE',
          action: {
            url: `${page.url}?ref_loc=search`,
          },
        }),
      )
    }
  }

  async handleEvent(event: QueryEvent) {
    const path = window.location.pathname
    const isHomePagePath = path === '/' || path === '/home'
    const isMarketingPagePath = ExplorePages.some(page => page.url.startsWith('/') && path.startsWith(page.url))

    // @ts-expect-error - Unfortunately, Vitest's browser mode modifies location.pathname
    if (!isHomePagePath && !isMarketingPagePath && !window.__vitest_browser__) {
      // We only want to show suggestions on the homepage and marketing pages
      return []
    }

    const state = event.parsedMetadata as ParsedIntermediateRepresentation | undefined
    if (!state?.query) {
      await this.#addDefaultSuggestions()
      return []
    }

    if (this.#querySuggestions === null) {
      this.#querySuggestions = await this.#fetchQuerySuggestions()
    }

    // make sure we only suggest for terms that are user typed content (number, text etc.)
    let term = state?.query
    if (state?.caretSelectedNode && isQualifier(state?.caretSelectedNode)) {
      if (isContentNode(state.caretSelectedNode.content)) {
        term = state.caretSelectedNode.content.value as string
      } else {
        term = ''
      }
    }

    let matches = this.#querySuggestions
    if (term && term.length > 0) {
      const fuzzyQuery = term.replace(/\s/g, '')
      const key = (page: ExplorePage) => {
        const score = fuzzyScore(page.title, fuzzyQuery)
        return score > 0 ? {score, text: page.title} : null
      }
      matches = filterSort(this.#querySuggestions, key, compare)
    }

    for (const page of matches.slice(0, 5)) {
      this.dispatchEvent(
        new SearchItem({
          value: page.title,
          icon: page.octicon as Octicon,
          priority: resultsPriority,
          scope: 'EXPLORE',
          action: {
            url: `${page.url}?q=${term}&ref_loc=search`,
          },
        }),
      )
    }
  }
}

