import {controller, target} from '@github/catalyst'
import {getBaseFetchHeaders} from '@github-ui/fetch-headers'

@controller('export-branch')
class ExportBranchElement extends HTMLElement {
  @target declare form: HTMLFormElement
  @target declare loadingIndicator: HTMLElement
  @target declare viewBranchLink: HTMLAnchorElement
  abortPoll: AbortController | null = null

  connectedCallback() {
    this.abortPoll = new AbortController()
    if (!this.loadingIndicator.hidden) {
      this.startPoll()
    }
  }

  disconnectedCallback(): void {
    this.abortPoll?.abort()
  }

  applyPublishParams() {
    const codespaceId = this.form.getAttribute('data-codespace-id')
    const publishForm = document.querySelector<HTMLFormElement>(
      `[data-codespace-id='${codespaceId}'][data-class="publish-codespace-form"]`,
    )
    if (publishForm) {
      const publishFormData = Object.fromEntries(new FormData(publishForm).entries())
      if (this.form) {
        const queryString = `?name=${publishFormData.name}&visibility=${publishFormData.visibility}`
        const updatedUrl = (this.form.getAttribute('action') || '').split('?')[0] + queryString
        this.form.setAttribute('action', updatedUrl)
      }
    }
  }

  async exportBranch(event: Event) {
    event.preventDefault()

    // Show the loading indicator immediately on click, which behaves more
    // like all the buttons throughout the app using data-disable-with.
    this.form.hidden = true
    this.loadingIndicator.hidden = false

    const response = await fetch(this.form.action, {
      method: this.form.method,
      body: new FormData(this.form),
      headers: {
        // We're passing *both* the Accept header and the XHR header. Ideally
        // we'd *only* pass Accept but currently the SAML filter only returns a
        // 401 for XHR requests. So we need to pass both headers to get the
        // behavior we want here.
        Accept: 'text/fragment+html',
        ...getBaseFetchHeaders(),
      },
    })

    if (response.ok) {
      this.startPoll()
    } else {
      this.form.hidden = false
      this.loadingIndicator.hidden = true
    }
  }

  private async startPoll() {
    const url = this.getAttribute('data-exported-codespace-url') || ''
    const response = await this.poll(url)
    if (response) {
      if (response.ok) {
        this.loadingIndicator.hidden = true
        this.viewBranchLink.hidden = false
      } else {
        const errorRedirectUrl = this.getAttribute('data-export-error-redirect-url') || ''
        window.location.href = encodeURI(errorRedirectUrl)
      }
    }
  }

  private async poll(url: string, wait = 1000): Promise<Response | undefined> {
    // The AbortController will be aborted if the component is disconnected (i.e. removed from the DOM)
    if (this.abortPoll?.signal.aborted) {
      return undefined
    }
    const response = await fetch(url, {signal: this.abortPoll?.signal})
    if (response.status === 202 || response.status === 404) {
      await new Promise(resolve => setTimeout(resolve, wait))
      return this.poll(url, wait * 1.5)
    }
    return response
  }
}

// Favicon manager
//
// Manages light and dark favicon variations, and handles status,
// showing a ✕, check, or pending dot over depending on the page status
import {observe} from '@github/selector-observer'
import {SOFT_NAV_STATE} from '@github-ui/soft-nav/states'
import {resetFavicon, syncFaviconToTheme, updateFaviconByHref} from '@github-ui/favicon'

observe('[data-favicon-override]', {
  add(el) {
    const href = el.getAttribute('data-favicon-override')!

    // allow `remove` for the old element to fire first
    setTimeout(() => updateFaviconByHref(href))
  },
  remove() {
    resetFavicon()
  },
})

syncFaviconToTheme()

document.addEventListener(SOFT_NAV_STATE.SUCCESS, syncFaviconToTheme)

window.matchMedia('(prefers-color-scheme: dark)').addListener(() => {
  syncFaviconToTheme()
})

import {observe} from '@github/selector-observer'

observe('.js-feature-preview-indicator-container', container => {
  fetchFeaturePreviewIndicator(container)
})

type FeatureResponse = {
  show_indicator: boolean
}

// Load the indicator status and update any indicators on the page.
async function fetchFeaturePreviewIndicator(container: Element) {
  const url = container.getAttribute('data-feature-preview-indicator-src')!
  const show = await fetchIndicator(url)
  const indicators = container.querySelectorAll<HTMLElement>('.js-feature-preview-indicator')
  for (const indicator of indicators) {
    indicator.hidden = !show
  }
}

async function fetchIndicator(url: string): Promise<boolean> {
  try {
    const response = await fetch(url, {headers: {Accept: 'application/json'}})
    if (!response.ok) return false
    const json = (await response.json()) as FeatureResponse
    return json.show_indicator
  } catch {
    return false
  }
}

import {fire, on} from 'delegated-events'
import {dialog} from '@github-ui/details-dialog'
import {fetchSafeDocumentFragment} from '@github-ui/fetch-utils'
import {remoteForm} from '@github-ui/remote-form'
import {sendStats} from '@github-ui/stats'

/*
  Opens the feature preview dialog to a given feature specified by it's slug

  <button data-feature-preview-trigger-url="<%= feature_previews_path(user_id: login, selected_slug: "my_feature") %>">
    Opt in to the feature preview for My Feature
  </button>

  You can react to a feature being enrolled/unenrolled by the user with these events:

  - `feature-preview-enroll:my_feature`
  - `feature-preview-unenroll:my_feature`

  e.g.

  document.addEventListener('feature-preview-enroll:my_feature', () => {
    optInButton.hidden = true
    optOutButton.hidden = false
  })

  document.addEventListener('feature-preview-unenroll:my_feature', () => {
    optInButton.hidden = false
    optOutButton.hidden = true
  })
*/

on('click', '[data-feature-preview-trigger-url]', async event => {
  const trigger = event.currentTarget
  const url = trigger.getAttribute('data-feature-preview-trigger-url')!

  const newDialog = await dialog({
    content: fetchSafeDocumentFragment(document, url),
    dialogClass: 'feature-preview-dialog',
  })

  const closeDetails = trigger.getAttribute('data-feature-preview-close-details')!
  const closeHmac = trigger.getAttribute('data-feature-preview-close-hmac')!

  newDialog.addEventListener('dialog:remove', () => {
    sendStats({hydroEventPayload: closeDetails, hydroEventHmac: closeHmac}, true)
  })

  const indicators = document.querySelectorAll<HTMLElement>('.js-feature-preview-indicator')
  for (const indicator of indicators) {
    indicator.hidden = true
  }
})

remoteForm('.js-feature-preview-unenroll', async (form, wants) => {
  await wants.text()
  const feature = form.querySelector<HTMLInputElement>('.js-feature-preview-slug')!.value
  fire(form, `feature-preview-unenroll:${feature}`)
})

remoteForm('.js-feature-preview-enroll', async (form, wants) => {
  await wants.text()
  const feature = form.querySelector<HTMLInputElement>('.js-feature-preview-slug')!.value
  fire(form, `feature-preview-enroll:${feature}`)
})

import {resetState, upload} from '../upload/batch-upload'
import Batch from '../upload/batch'
import type FileAttachmentElement from '@github/file-attachment-element'
import {observe} from '@github/selector-observer'
import {on} from 'delegated-events'

// Synchronize element state with primer styles. This should be replaced with CSS.
observe('file-attachment[hover]', {
  add(el) {
    el.classList.add('dragover')
  },
  remove(el) {
    el.classList.remove('dragover')
  },
})

// Cancel empty drops after filtering out hidden dot files.
on('file-attachment-accept', 'file-attachment', function (event) {
  const {attachments} = event.detail
  if (attachments.length === 0) {
    resetState(event.currentTarget, 'is-hidden-file')
    event.preventDefault()
  }
})

// Upload batched files after passing validation.
on('file-attachment-accepted', 'file-attachment', function (event) {
  // CodeEditor will hide this element if it wants to handle uploads
  const dragAndDropLabel = event.currentTarget.querySelector<HTMLElement>('.drag-and-drop')
  if (dragAndDropLabel && dragAndDropLabel.hidden) {
    return
  }

  const {attachments} = event.detail
  upload(new Batch(attachments), event.currentTarget as FileAttachmentElement)
})

// Transfer click on button to hidden file input.
on('click', 'button[data-file-attachment-for]', function (event) {
  const button = event.currentTarget as HTMLButtonElement
  const inputId = button.getAttribute('data-file-attachment-for')
  const input = document.querySelector<HTMLInputElement>(`input[type=file]#${inputId}`)!
  input.click()
})

let count = 0

observe('file-attachment', {
  add(el) {
    if (count++ === 0) {
      document.addEventListener('drop', onDocumentDrop)
      document.addEventListener('dragover', onDocumentDragover)
    }
    const form = el.closest('form')
    if (form) {
      form.addEventListener('reset', onFormReset)
    }
  },
  remove(el) {
    if (--count === 0) {
      document.removeEventListener('drop', onDocumentDrop)
      document.removeEventListener('dragover', onDocumentDragover)
    }

    const form = el.closest('form')
    if (form) {
      form.removeEventListener('reset', onFormReset)
    }
  },
})

function hasFile(transfer: DataTransfer): boolean {
  return Array.from(transfer.types).indexOf('Files') >= 0
}

// Ignores accidental drops that miss the textarea.
function onDocumentDrop(event: DragEvent) {
  const transfer = event.dataTransfer
  if (transfer && hasFile(transfer)) {
    event.preventDefault()
  }
}

// Prevent accidental drops until we're over a textarea.
function onDocumentDragover(event: DragEvent) {
  const transfer = event.dataTransfer
  if (transfer && hasFile(transfer)) {
    event.preventDefault()
  }
}

// Parent form has been reset. Reset uploadable state back to default.
function onFormReset({currentTarget}: Event) {
  const container = (currentTarget as Element).querySelector<HTMLElement>('file-attachment')!
  resetState(container, 'is-default')
}

import {fromEvent} from '@github-ui/subscription'
import hashChange from '../behaviors/hash-change'
import {observe} from '@github/selector-observer'
import {on} from 'delegated-events'
import {scrollIntoView} from '../sticky-scroll-into-view'
import {updateURLState} from './file-filter-persistence'

on('details:toggled-group', '.js-file.js-details-container', function (event) {
  if (event.target !== event.currentTarget) return
  toggledAllFileContents(event.detail.open)
})

// Scroll file header into view if top of file is offscreen (sticky file header).
on('details:toggled', '.js-file.js-details-container', function (event) {
  if (event.target !== event.currentTarget) return
  const container = event.currentTarget
  if (container.getBoundingClientRect().top < 0) {
    scrollIntoView(container)
  }
})

hashChange(() => {
  const hash = window.location.hash.slice(1)
  if (!hash) return
  const target = document.getElementsByName(hash)[0]
  if (!target) return
  const container = target.nextElementSibling
  if (container && container.matches('.js-file.js-details-container')) {
    container.classList.add('open')
    container.classList.add('Details--on')
  }
})

observe('.js-file-header-dropdown', {
  subscribe: el => fromEvent(el, 'toggle', toggleFileHeaderMenu),
})

// Adjusts the z-index of a file header with an open dropdown menu to ensure
// it's always visible atop the other files. Otherwise, the open menu of a
// collapsed file is displayed beneath the next file.
function toggleFileHeaderMenu({currentTarget}: Event) {
  const details = currentTarget as Element
  const isOpen = details.hasAttribute('open')
  const file = details.closest<HTMLElement>('.js-file-header')!
  file.classList.toggle('has-open-dropdown', isOpen)
}

function toggledAllFileContents(open: boolean) {
  const fileFilter = document.querySelector('.js-file-filter')
  if (!fileFilter) {
    return
  }

  // Toggle all file type inputs with given checked value
  const fileTypeOptions = getFileTypeOptions()
  for (const checkbox of fileTypeOptions) {
    checkbox.checked = open
  }

  const deletedFilesInput = getDeletedFilesInput()
  if (deletedFilesInput) {
    deletedFilesInput.checked = !open
  }

  const isActive = fileFilterActive()

  toggleHighlightActiveFilter(isActive)
  toggleResetFileFiltersButton(isActive)
  toggleAvailableOptions()
  toggleSelectAll()
  toggleFileTypeCounts()
  updateURLState(
    isActive,
    whitespaceFilterActive(),
    getSelectedFileTypes(),
    codeownerFilterActive(),
    getSelectedOwners(),
    manifestFilterActive(),
    deletedFilterActive(),
    viewedFilterActive(),
  )
}

// Get file type names that have be selected through the checkboxes
function getSelectedFileTypes(): string[] {
  const checkedFileOptions = Array.from(getFileTypeOptions()).filter(option => option.checked)
  return checkedFileOptions.map(option => option.value)
}

// Get checkbox elements for the file types in the diff
function getFileTypeOptions() {
  return document.querySelectorAll<HTMLInputElement>('.js-diff-file-type-option')
}

// Get deleted files checkbox
function getDeletedFilesInput(): HTMLInputElement | undefined {
  const input = document.querySelector('.js-deleted-files-toggle')
  if (input instanceof HTMLInputElement) {
    return input
  }
}

// Are any files being filtered?
function fileFilterActive(): boolean {
  return (
    fileTypeFilterActive() ||
    deletedFilterActive() ||
    viewedFilterActive() ||
    codeownerFilterActive() ||
    manifestFilterActive()
  )
}

function codeownerFilterActive(): boolean {
  return getSelectedOwners().length > 0
}

function getSelectedOwners(): string[] {
  const ownerOptions = document.querySelectorAll<HTMLInputElement>('.js-diff-owner-option')
  const checkedFileOptions = Array.from(ownerOptions).filter(option => option.checked)
  return checkedFileOptions.map(option => option.value)
}

// Are any files being filtered by type?
function fileTypeFilterActive(): boolean {
  return getSelectedFileTypes().length !== getFileTypeOptions().length
}

// Are any files being filtered by manifest status?
function manifestFilterActive(): boolean {
  const showManifestFiles = document.querySelector<HTMLInputElement>('.js-manifests-option')
  if (showManifestFiles) {
    return showManifestFiles.checked
  } else {
    return false
  }
}

// Are any files being filtered by deleted status?
function deletedFilterActive(): boolean {
  const hideDeletedFiles = getDeletedFilesInput()
  if (hideDeletedFiles) {
    return !hideDeletedFiles.checked
  } else {
    return false
  }
}

// Are any files being filtered by viewed status?
function viewedFilterActive(): boolean {
  const input = document.querySelector<HTMLInputElement>('.js-viewed-files-toggle')
  if (input) {
    return !input.checked
  } else {
    return false
  }
}

// Has the whitespace "w" url parameter been passed
function whitespaceFilterActive(): boolean {
  const params = new URLSearchParams(window.location.search)
  return params.has('w')
}

// Changes the file filter drop down button to show if the filter is active
function toggleHighlightActiveFilter(highlight: boolean) {
  const fileFilterButton = document.querySelector<HTMLElement>('.js-file-filter-text')!
  fileFilterButton.classList.toggle('color-fg-accent', highlight)
}

// Shows or hides the 'Reset' CTA
function toggleResetFileFiltersButton(show: boolean) {
  const resetFileFilter = document.querySelector('.js-reset-filters')
  const commitsCurrentlyFiltered = document.querySelector('.js-commits-filtered')

  if (resetFileFilter != null && !commitsCurrentlyFiltered) {
    ;(resetFileFilter as HTMLElement).hidden = !show
  }
}

// Toggles text for select all file types cta
function toggleSelectAll() {
  const typefilterActive = fileTypeFilterActive()
  const selectAllContainer = document.querySelector<HTMLElement>('.js-file-filter-select-all-container')!
  const selectedMarkup = typefilterActive ? 'data-select-all-markup' : 'data-all-selected-markup'
  const newMarkup = selectAllContainer.getAttribute(selectedMarkup)!
  selectAllContainer.textContent = newMarkup
  selectAllContainer.classList.toggle('color-fg-muted', !typefilterActive)
  selectAllContainer.classList.toggle('color-fg-accent', typefilterActive)
}

// Toggles which filters are disabled given other filters
function toggleAvailableOptions() {
  // Disables file types that consist of only deleted files when deleted files filter is active
  const fileTypeOptions = getFileTypeOptions()
  const deletedFilesHidden = deletedFilterActive()
  for (const checkbox of fileTypeOptions) {
    if (deletedFilesHidden) {
      const allFilesDeleted = checkbox.getAttribute('data-non-deleted-files-count') === '0'
      checkbox.disabled = allFilesDeleted
    } else {
      checkbox.disabled = false
    }
  }
}

function toggleFileTypeCounts() {
  const fileTypeCounts = document.querySelectorAll('.js-file-type-count')
  for (const count of fileTypeCounts) {
    const countMarkup = deletedFilterActive() ? 'data-non-deleted-file-count-markup' : 'data-all-file-count-markup'

    const newMarkup = count.getAttribute(countMarkup)
    if (newMarkup) {
      count.textContent = newMarkup
    }
  }
}

import {on} from 'delegated-events'

// Shows blankslate if files empty
function checkEmptyFilterResults() {
  const blankSlate = document.querySelector<HTMLInputElement>('.js-file-filter-blankslate')
  if (!blankSlate) {
    return
  }

  const loaders = document.querySelectorAll<HTMLInputElement>('.js-diff-progressive-loader')
  if (loaders.length > 0) {
    blankSlate.hidden = true
    return
  }

  const filesOnPage = document.querySelectorAll<HTMLInputElement>('.js-file')
  if (filesOnPage.length === 0) {
    blankSlate.hidden = true
    return
  }

  const isNotEmpty = Array.from(filesOnPage).some(file => !file.hidden)
  blankSlate.hidden = isNotEmpty
}

// Unhides file if hidden by filter and you click to it from jump to menu
on('click', '.js-jump-to-menu-item', function ({currentTarget}) {
  const anchorValue = currentTarget.getAttribute('href')!.substring(1)
  const dataAnchor = document.querySelector(`[data-anchor="${anchorValue}"]`)!
  if (dataAnchor) {
    const file = dataAnchor.closest<HTMLElement>('.js-file.js-details-container')!
    file.hidden = false
  }
  checkEmptyFilterResults()
})

import {updateUrl} from '@github-ui/history'

export function updateURLState(
  fileFiltersActive: boolean,
  whitespaceFilterActive: boolean,
  selectedTypes: string[],
  selectedOwnersActive: boolean,
  selectedOwners: string[],
  manifestsFilterActive: boolean,
  deletedFilesHidden: boolean,
  viewedFilesHidden: boolean,
  // useful for testing
  searchParamString = window.location.search,
) {
  const fileFilter = document.querySelector<HTMLElement>('.js-file-filter')!
  const url = new URL(window.location.href, window.location.origin)
  const activeSearchParams = new URLSearchParams(searchParamString)
  const whitespaceParam = activeSearchParams.get('w')

  if (!fileFiltersActive && !selectedOwnersActive) {
    if (manifestsFilterActive) {
      return
    }

    // keep the 'diff' and 'w' params if the file filter are not active
    const params = new URLSearchParams()
    const diffParam = activeSearchParams.get('diff')
    if (diffParam) params.set('diff', diffParam)
    if (whitespaceParam) params.set('w', whitespaceParam)

    url.search = params.toString()
    updateUrl(url.toString())
    return
  }

  const fileFilterForm = fileFilter.querySelector<HTMLFormElement>('.js-file-filter-form')!
  const formData = new FormData(fileFilterForm)
  const disabledSelectedTypes = selectedTypes.filter(type => !formData.getAll('file-filters[]').includes(type))
  const disabledSelectedOwners = selectedOwners.filter(owner => !formData.getAll('owned-by[]').includes(owner))

  // Add selected but disabled types
  for (const disabledType of disabledSelectedTypes) {
    formData.append('file-filters[]', disabledType)
  }

  for (const disabledOwner of disabledSelectedOwners) {
    formData.append('owned-by[]', disabledOwner)
  }

  const params = new URLSearchParams(formData as unknown as URLSearchParams)

  if (!params.has('file-filters[]') || params.toString() === '') {
    // Filter is active, but no file types are selected
    params.set('file-filters[]', '')
  }

  if (whitespaceFilterActive) {
    params.set('w', whitespaceParam ?? '1')
  }

  if (manifestsFilterActive) {
    params.set('manifests', 'true')
  }

  if (deletedFilesHidden) {
    params.set('show-deleted-files', 'false')
  }

  if (viewedFilesHidden) {
    params.set('show-viewed-files', 'false')
  }

  /* eslint-disable-next-line github/authenticity-token */
  params.delete('authenticity_token')

  url.search = params.toString()
  updateUrl(url.toString())
}

import {AccessPolicyItem} from '../items/access-policy-item'
import {JumpToItem} from '../items/jump-to-item'
import {PrefetchedProvider} from './prefetched-provider'
import {Query} from '../query'
import type {ServerDefinedItem} from '../items/server-defined-item'
import {getBaseFetchHeaders} from '@github-ui/fetch-headers'

/**
 * This is a special prefetched provider that supports linking to file line
 * numbers using the `:123` syntax. This happens in the browser.
 *
 */

export class FilesProvider extends PrefetchedProvider {
  /**
   * Fetch results from server and serialize into JumpToItems using file paths.
   */
  override async fetchSrc(query: Query) {
    if (!this.src) throw new Error('No src provided')

    const url = new URL(this.src, window.location.origin)
    url.search = query.params().toString()
    const response = await fetch(url.toString(), {
      headers: {
        Accept: 'application/json',
        ...getBaseFetchHeaders(),
      },
    })

    const data = await response.json()
    if (!data.results) return

    const results = data.results[0]

    if (results['base_file_path']) {
      const baseFilePath = results['base_file_path'] as string
      const filePaths = results.paths as string[]
      data.results = filePaths.map(file => {
        return JumpToItem.from({
          title: file,
          path: `${baseFilePath}/${file}`,
          icon: 'file-color-fg-muted',
          group: 'files',
        })
      })
    } else if (results['action'] && results.action.type === 'access_policy') {
      data.results = [new AccessPolicyItem(results)]
    } else {
      data.results = []
    }

    return data
  }

  override async fetch(query: Query, isEmpty = false) {
    const endsWithLineNumberMatch = query.text.match(/(.+):(\d*)\s*$/)

    if (endsWithLineNumberMatch) {
      return this.fetchWithLineNumbers(query, endsWithLineNumberMatch)
    } else {
      return super.fetch(query, isEmpty)
    }
  }

  /**
   * Build and return a list of items that link to a line number in a file. This
   * relies on super.fetch to return items matching the query without the line
   * number and then appends the line number afterwards.
   *
   * @param query
   * @param endsWithLineNumberMatch
   * @returns list of file jump to items linking to a line number
   */
  async fetchWithLineNumbers(query: Query, endsWithLineNumberMatch: RegExpMatchArray) {
    const newQueryText = endsWithLineNumberMatch[1]!
    const lineNumber = endsWithLineNumberMatch[2]!
    const queryWithoutLineNumber = new Query(newQueryText, query.mode, {scope: query.scope})

    const items = [] as ServerDefinedItem[]
    const superItems = (await super.fetch(queryWithoutLineNumber, false)).results
    for (const item of superItems) {
      if (item instanceof JumpToItem) {
        items.push(this.convert(item, lineNumber))
      }
    }

    return {results: items}
  }

  /**
   * This takes an item and returns a new one with a line number attached. This
   * builds a new item, it doesn't mutate the original.
   *
   * If the line number is empty or the item isn't a JumpToItem, the same item is
   * returned.
   *
   * @param item to be converted
   * @param lineNumber to append to item
   * @returns item with line number append, if appropriate
   */
  convert(item: ServerDefinedItem, lineNumber: string) {
    if (lineNumber === '') return item
    if (!(item instanceof JumpToItem)) return item

    item.title = `${item.title}:${lineNumber}`
    item.action.path = `${item.action.path}#L${lineNumber}`

    return item
  }
}

// Filterable Behavior
//
// Automatically filters and sorts a list of items against a text field.
//
// Markup
//
// * js-filterable-field  - Set on field to enable filtering.
// * data-filterable-for  - Set to ID of input field to bind too.
// * data-filterable-type - Filtering type. Either "prefix", "substring", "fuzzy", or "fuzzy-prio". Defaults to "prefix"
// The difference between "fuzzy" and "fuzzy-prio", is the latter supports an additional attribute `data-prio-filter-value`
// to specify a custom priority value that will be weighted more heavily when determining the score.
//
// <input id="file-filter-field" class="js-filterable-field" autocomplete="off">
//
// <ul data-filterable-for="file-filter-field" data-filterable-type="fuzzy">
//   <li>Foo</li>
//   <li>Bar</li>
//   <li>Baz</li>
// </ul>
//
//
// Events
//
// filterable:change
//
// * **Bubbles** Yes
// * **Cancelable** No
// * **Target** List container Element
// * **Context info**
//   * relatedTarget - Input field Element
//
// $('ul').on('filterable:change', function() {
//   console.log('order changed')
// })
//

import {addThrottledInputEventListener, removeThrottledInputEventListener} from '../throttled-input'
import {fire, on} from 'delegated-events'
import {announce} from '@github-ui/aria-live'
import {filterList} from '../filter-list'
import {filterSortList} from '../filter-sort-list'
import {fuzzyScore} from '@github-ui/fuzzy-filter'
import {microtask} from '@github-ui/eventloop-tasks'
import {observe} from '@github/selector-observer'
import {substringMemoryFilterList} from '../substring-memory-filter-list'
import {labelsTypeaheadFilterList} from '../labels-typeahead-filter-list'

observe('.js-filterable-field', {
  constructor: HTMLInputElement,
  initialize(field) {
    if (!field.autocomplete) {
      field.autocomplete = 'off'
    }

    // A null value will default to whatever is specified within `throttled-input.ts`
    const throttleWaitInMs = field.hasAttribute('type-ahead') ? 200 : null
    let value = field.value

    async function onInputChange(input: HTMLInputElement | HTMLTextAreaElement) {
      if (value === input.value) return
      value = input.value
      await microtask()
      fire(input, 'filterable:change')
    }

    async function onFocus() {
      value = field.value
      await microtask()
      fire(field, 'filterable:change')
    }

    return {
      add(el) {
        el.addEventListener('focus', onFocus)
        addThrottledInputEventListener(el, onInputChange, {wait: throttleWaitInMs})
        if (document.activeElement === el) onFocus()
      },
      remove(el) {
        el.removeEventListener('focus', onFocus)
        removeThrottledInputEventListener(el, onInputChange)
      },
    }
  },
})

// Trigger 'filterable:change' on an input after any
// direct val() calls
on('filterable:change', '.js-filterable-field', async function (event: Event) {
  const target = event.currentTarget as HTMLInputElement
  const queryString = target.value.trim().toLowerCase()
  const filterable = document.querySelectorAll(`[data-filterable-for="${target.id}"]`)
  for (const list of filterable) {
    const visible = await filter(list, queryString)
    if (visible === -1) return
    if (document.activeElement && target === document.activeElement) {
      announce(`${visible} results found.`)
    }

    list.dispatchEvent(
      new CustomEvent('filterable:change', {
        bubbles: true,
        cancelable: false,
        detail: {
          inputField: target,
        },
      }),
    )
  }
})

function defaultText(content: Element): string {
  return content.hasAttribute('data-filter-value')
    ? content.getAttribute('data-filter-value')!.toLowerCase().trim()
    : content.textContent.toLowerCase().trim()
}

async function filter(list: Element, queryString: string): Promise<number> {
  const limit = parseInt(list.getAttribute('data-filterable-limit')!, 10) || null

  let visible = 0
  switch (list.getAttribute('data-filterable-type')) {
    case 'fuzzy-prio': {
      const searchQuery = queryString.toLowerCase()
      const sortKey = (item: HTMLElement) => {
        const prioText = item.getAttribute('data-prio-filter-value')!.toLowerCase().trim()
        const text = item.textContent.toLowerCase().trim()

        // Increase the weighting of the score of the custom priority value
        const prioScore = fuzzyScore(prioText, searchQuery, 0.01) * 2
        let score = fuzzyScore(text, searchQuery, 0.01)
        if (prioScore > score) score = prioScore

        return score > 0 ? {score, text} : null
      }
      visible = filterSortList(list, queryString, {limit, sortKey})
      break
    }
    case 'fuzzy': {
      const searchQuery = queryString.toLowerCase()
      const sortKey = (item: HTMLElement) => {
        const text = defaultText(item)
        const score = fuzzyScore(text, searchQuery)
        return score > 0 ? {score, text} : null
      }
      visible = filterSortList(list, queryString, {limit, sortKey})
      break
    }
    case 'substring':
      visible = filterList(list, queryString.toLowerCase(), substring, {limit})
      break
    case 'substring-memory':
      visible = await substringMemoryFilterList(list, queryString, {limit})
      break
    case 'labels-typeahead':
      visible = await labelsTypeaheadFilterList(list, queryString, {limit})
      break
    default:
      visible = filterList(list, queryString.toLowerCase(), prefix, {limit})
      break
  }

  list.classList.toggle('filterable-active', queryString.length > 0)
  list.classList.toggle('filterable-empty', visible === 0)

  return visible
}

function prefix(el: Element, queryString: string): boolean {
  return el.textContent.toLowerCase().trim().startsWith(queryString)
}

// Does the text of the given element match the given query string?
//
// Note: you can add a `data-skip-substring-filter` attribute to exclude an
// element from substring filtering.
//
// Returns Boolean or null, if element cannot be filtered
function substring(el: Element, queryString: string): boolean | null {
  if (el.hasAttribute('data-skip-substring-filter')) return null
  if (el.classList.contains('select-menu-no-results')) return null
  const target = el.querySelector('[data-filterable-item-text]') || el
  return target.textContent.toLowerCase().trim().includes(queryString)
}

// Toggle new create new item form when filter doesn't match any existing items
on('filterable:change', 'details-menu .select-menu-list', function (event) {
  const list = event.currentTarget
  const form = list.querySelector('.js-new-item-form')

  if (form) {
    toggleForm(list, form, event.detail.inputField.value)
  }
})

function toggleForm(list: Element, form: Element, filterText: string) {
  const show = filterText.length > 0 && !itemExists(list, filterText)
  list.classList.toggle('is-showing-new-item-form', show)

  if (!show) return

  form.querySelector<HTMLElement>('.js-new-item-name')!.textContent = filterText

  const item = form.querySelector('.js-new-item-value')
  if (item instanceof HTMLInputElement || item instanceof HTMLButtonElement) {
    item.value = filterText
  }
}

// Detect if filtered item is already present in the list.
//
// container  - filterable list element
// filterText - String value of filter field
//
// Returns true if item already exists, otherwise false.
function itemExists(container: Element, filterText: string): boolean {
  for (const item of container.querySelectorAll('[data-menu-button-text]')) {
    const text = (item as HTMLElement).textContent.toLowerCase().trim()
    if (text === filterText.toLowerCase()) {
      return true
    }
  }
  return false
}

// Hoist empty class to parent for styling.
observe('tab-container .select-menu-list .filterable-empty, details-menu .select-menu-list .filterable-empty', {
  add(el) {
    const list = el.closest<HTMLElement>('.select-menu-list')!
    list.classList.add('filterable-empty')
  },
  remove(el) {
    const list = el.closest<HTMLElement>('.select-menu-list')!
    list.classList.remove('filterable-empty')
  },
})

import FilterInputElement from '@github/filter-input-element'
import {announce} from '@github-ui/aria-live'
import {on} from 'delegated-events'

// Use data- attributes on the <filter-input> element to construct the options arguments to pass to
// announce().
function announceOptions(filterElement: FilterInputElement) {
  const ariaLiveRegionId = filterElement.getAttribute('data-aria-live-element')
  if (!ariaLiveRegionId) return {}

  const ariaLiveRegion = document.getElementById(ariaLiveRegionId)
  if (!ariaLiveRegion) return {}

  return {element: ariaLiveRegion}
}

on('filter-input-updated', 'filter-input', event => {
  const filterElement = event.target as FilterInputElement
  const input = filterElement.input
  if (!(document.activeElement && document.activeElement === input)) return

  const {count, total} = event.detail
  const options = announceOptions(filterElement)

  // eslint-disable-next-line i18n-text/no-en
  announce(`Found ${count} out of ${total} ${total === 1 ? 'item' : 'items'}`, options)
})

on(
  'toggle',
  'details',
  event => {
    // Wait for the next click to ensure that focus has left input
    setTimeout(() => resetFilter(event.target as Element), 0)
  },
  {capture: true},
)

on(
  'tab-container-changed',
  'tab-container',
  event => {
    if (!(event.target instanceof HTMLElement)) return
    const {relatedTarget: panel} = event.detail
    const filterInput = event.target.querySelector('filter-input')
    if (panel && filterInput instanceof FilterInputElement) {
      filterInput.setAttribute('aria-owns', panel.id)
    }
  },
  {capture: true},
)

function resetFilter(target: Element) {
  const filterInput = target.querySelector<FilterInputElement>('filter-input')
  if (filterInput && !target.hasAttribute('open')) {
    filterInput.reset()
  }
}

type Predicate = (el: Element, query: string) => boolean | null
type Options = {limit?: number | null}

export function filterList(list: Element, query: string, isVisible: Predicate, options: Options = {}): number {
  const limit = options.limit ?? Infinity
  let visible = 0
  for (const item of list.children) {
    const show = isVisible(item, query)
    if (show == null) {
      // ignore
    } else if (show && visible < limit) {
      visible++
      toggle(item as HTMLElement, true)
    } else {
      toggle(item as HTMLElement, false)
    }
  }
  return visible
}

function toggle(el: HTMLElement, show: boolean) {
  el.style.display = show ? '' : 'none'
  el.hidden = !show
}

import type {TextScore} from '@github-ui/fuzzy-filter'
import {compare} from '@github-ui/fuzzy-filter'
import {filterSort} from '@github-ui/filter-sort'

const originalOrder = new WeakMap<Element, HTMLElement[]>()

interface FilterOptions {
  limit?: number | null
  sortKey: (item: HTMLElement) => TextScore | null | undefined
}

// Filters and sorts list element items against a text query. For use with lists that
// are already in the DOM, not with lists of results that are changed dynamically
// via ajax.
//
// Returns Number of visible items.
export function filterSortList(list: Element, string: string, options: FilterOptions): number {
  const query = string.toLowerCase()
  const limit = options.limit

  let allItems = originalOrder.get(list)
  const checkedInputBeforeFilter = list.querySelector('input[type="radio"]:checked')
  const children = Array.from(list.children)
  if (!allItems) {
    allItems = Array.from(list.children) as HTMLElement[]
    originalOrder.set(list, allItems)
  } else if (list.classList.contains('filter-sort-list-refresh')) {
    // if we get this class, it means the items in the list might have been changed
    // in this case, we check if there are new items to be added to the cache
    // this is the case when creating a new label from the label picker (see app/assets/modules/github/issues/labels.ts)
    list.classList.remove('filter-sort-list-refresh')
    const currentItems = Array.from(list.children) as HTMLElement[]
    for (const currentItem of currentItems) {
      if (!allItems.includes(currentItem)) {
        allItems.push(currentItem)
      }
    }
  }
  for (const item of children) {
    list.removeChild(item)
    if (item instanceof HTMLElement) item.style.display = ''
  }

  const found = query ? filterSort(allItems, options.sortKey, compare) : allItems
  const limited = limit == null ? found : found.slice(0, limit)
  const visible = limited.length
  const results = document.createDocumentFragment()
  for (const item of limited) {
    results.appendChild(item)
  }

  // This ensures that checked input before and after filtering is the same one
  // See https://github.com/github/github/issues/88129#issuecomment-434839397
  let inputStateReset = false
  if (checkedInputBeforeFilter instanceof HTMLInputElement) {
    for (const checkedInput of results.querySelectorAll('input[type="radio"]:checked')) {
      if (checkedInput instanceof HTMLInputElement && checkedInput.value !== checkedInputBeforeFilter.value) {
        checkedInput.checked = false
        inputStateReset = true
      }
    }
  }

  list.appendChild(results)

  // Dispatch a change event after render for details-menu or any other code reacting to the input state
  if (checkedInputBeforeFilter && inputStateReset) {
    checkedInputBeforeFilter.dispatchEvent(new Event('change', {bubbles: true}))
  }

  return visible
}

import {filterSort} from '@github-ui/filter-sort'
import {compare, fuzzyScore} from '@github-ui/fuzzy-filter'
import type {QueryEvent, FilterProvider} from '@github-ui/query-builder-element/query-builder-api'
import {FilterItem, Octicon} from '@github-ui/query-builder-element/query-builder-api'
import type {QueryBuilderElement} from '@github-ui/query-builder-element'
import {CaretPositionKind, isContentNode, isQualifier} from '../parsing/common'
import type {ParsedIntermediateRepresentation} from '../qbsearch-input-element'
import type {BaseNode} from '@github/blackbird-parser'
// eslint-disable-next-line import/no-namespace
import type * as Parsing from '../parsing/parsing'

export class FixedValuesProvider extends EventTarget implements FilterProvider {
  priority = 3
  name = 'Values'
  singularItemName = 'value'
  value = 'value'
  type = 'filter' as const
  manuallyDetermineFilterEligibility = true

  #parsing: typeof Parsing | undefined

  queryBuilder: QueryBuilderElement

  constructor(queryBuilder: QueryBuilderElement) {
    super()
    this.queryBuilder = queryBuilder
    this.queryBuilder.addEventListener('query', this)
  }

  async handleEvent(event: QueryEvent) {
    const state = event.parsedMetadata as ParsedIntermediateRepresentation | undefined

    if (!state) {
      return []
    }

    if (
      state.caretPositionKind !== CaretPositionKind.OtherQualifier &&
      state.caretPositionKind !== CaretPositionKind.Is
    ) {
      return []
    }

    if (!state.caretSelectedNode || !isQualifier(state.caretSelectedNode)) {
      return []
    }

    if (!this.#parsing) {
      this.#parsing = await import('../parsing/parsing')
    }

    let matches = []

    const isLicense = state.caretSelectedNode.qualifier === 'License'
    const isLanguage = state.caretSelectedNode.qualifier === 'Language'

    if (isLicense) {
      matches = [
        ['BSD Zero Clause License', '0bsd'],
        ['MIT License', 'mit'],
        ['Apache License 2.0', 'apache-2.0'],
        ['Creative Commons', 'cc'],
        ['GNU General Public License', 'gpl'],
        ['GNU Lesser General Public License', 'lgpl'],
      ]
    } else {
      matches = this.#parsing
        .getPossibleQualifierValues(
          this.#parsing.chooseSearchType(state.ast as BaseNode, true),
          state.caretSelectedNode.qualifier,
        )
        .map(r => [r, r])
    }

    let term = state.query
    if (state.caretSelectedNode && isQualifier(state.caretSelectedNode)) {
      if (isContentNode(state.caretSelectedNode.content)) {
        term = state.caretSelectedNode.content.value as string
      } else {
        term = ''
      }
    }

    if (term.length > 0) {
      const fuzzyQuery = term.replace(/\s/g, '')
      const key = (r: string[]) => {
        const t = r[0] === r[1] ? r[0]! : `${r[0]} ${r[1]}`
        const score = fuzzyScore(t, fuzzyQuery)
        return score > 0 ? {score, text: t} : undefined
      }
      matches = filterSort(matches, key, compare)
    }

    for (const suggestion of matches.slice(0, 5)) {
      if (state.caretSelectedNode && isQualifier(state.caretSelectedNode)) {
        let rewriteStart = state.caretSelectedNode.location.end
        let rewriteEnd = state.caretSelectedNode.location.end
        if (isContentNode(state.caretSelectedNode.content)) {
          rewriteStart = state.caretSelectedNode.content.location.start
          rewriteEnd = state.caretSelectedNode.content.location.end
        }

        const quotedValue = suggestion[1]!.includes(' ') ? `"${suggestion[1]}"` : suggestion[1]!

        const newQuery = `${state.query.slice(0, rewriteStart) + quotedValue} ${state.query.slice(rewriteEnd)}`
        const action = {
          replaceQueryWith: newQuery,
          moveCaretTo: rewriteStart + quotedValue.length + 1,
        }
        this.dispatchEvent(
          new FilterItem({
            filter: 'owner',
            value: suggestion[0]!,
            icon: isLanguage ? Octicon.Circle : undefined,
            priority: 0,
            action,
          }),
        )
      }
    }
  }
}

// Installs observer to account for sticky/fixed overlay offsets when navigating
// to a fragment.
import {computeFixedYOffset, scrollToFragmentTarget} from '../sticky-scroll-into-view'
import hashChange from './hash-change'
import {on} from 'delegated-events'
import {SOFT_NAV_STATE} from '@github-ui/soft-nav/states'

function scrollTargetIntoViewIfNeeded() {
  const root = document.firstElementChild! as HTMLHtmlElement
  if (root.classList.contains('js-skip-scroll-target-into-view')) return

  if (computeFixedYOffset()) {
    scrollToFragmentTarget(document)
  }
}

hashChange(scrollTargetIntoViewIfNeeded)

on('click', 'a[href^="#"]', function (event) {
  const {currentTarget} = event
  if (!(currentTarget instanceof HTMLAnchorElement)) return

  // this defers the execution of scrollTargetIntoViewIfNeeded until after all the click stuff happened, including after scroll
  setTimeout(scrollTargetIntoViewIfNeeded, 0)
})

// After a soft navigation, scroll to the fragment target if there is one.
// Turbo frame navigations restore the hash in the URL but don't scroll to it.
if (typeof document !== 'undefined') {
  document.addEventListener(SOFT_NAV_STATE.SUCCESS, () => {
    scrollToFragmentTarget(document)
  })
}

import {deleteCookie, getCookies} from '@github-ui/cookies'
import {TemplateInstance} from '@github/template-parts'

const ALLOWED_FLASH_COOKIES = ['flash-notice', 'flash-error', 'flash-message', 'flash-warn', 'flash-success']

// Find cookies named something like "flash-notice" and render the
// .js-flash-template template for them.
export function displayFlash(el: HTMLTemplateElement) {
  for (const {key, value} of ALLOWED_FLASH_COOKIES.flatMap(getCookies)) {
    deleteCookie(key)
    let message
    try {
      message = atob(decodeURIComponent(value))
    } catch {
      continue
    }
    el.after(new TemplateInstance(el, {className: key, message}))
  }
}

import {loaded} from '@github-ui/document-ready'

// Flash
//
// Fades out and removes flash element from the page on close.
//
// Markup
//
//     <div class="flash-messages">
//       <div class="flash">
//         <%= octicon('x', :class => 'flash-close js-flash-close') %>
//         Flash Message
//       </div>
//     </div>
//
import {on} from 'delegated-events'

// Only headings and focusable elements are allowed to be passed in as targets,
// otherwise they won't exist in the allFocusableElements array.
type FocusableElementsAndHeadings =
  | HTMLButtonElement
  | HTMLAnchorElement
  | HTMLInputElement
  | HTMLSelectElement
  | HTMLTextAreaElement
  | HTMLHeadingElement

// Ensures that focus is not lost when a user dismisses a flash message.
// Finds the closest, previous focusable element or <h1> that is not hidden or disabled and moves focus to that element.

const focusPreviousElementInDOM = (targetElement: FocusableElementsAndHeadings) => {
  // Get all focusable elements and headings (h1-h3) in the DOM that are not disabled or hidden
  const allFocusableElementsAndHeadings: FocusableElementsAndHeadings[] = Array.from(
    document.querySelectorAll(
      'h1:not([hidden]),h2:not([hidden]),h3:not([hidden]),button:not([disabled]):not([hidden]),a:not([hidden]),input:not([disabled]):not([hidden]), select:not([disabled]):not([hidden]), textarea:not([disabled]):not([hidden]), [tabindex]:not([tabindex="-1"]):not([disabled]):not([hidden])',
    ),
  )

  const visibleElements = Array.from(allFocusableElementsAndHeadings).filter(element => {
    // Check if the element and it's parent element is visible and not disabled or hidden
    if (
      !element.getAttribute('aria-hidden') &&
      !(element.offsetWidth <= 0 && element.offsetHeight <= 0) &&
      (element?.offsetParent as HTMLElement)?.style.visibility !== 'hidden'
    ) {
      return true
    }
  })

  const indexOfElement = visibleElements.indexOf(targetElement)

  if (indexOfElement !== -1 && indexOfElement > 0) {
    // Get the element right before the target element
    const elementBefore = visibleElements[indexOfElement - 1]
    // Forces the heading to have a tabindex of -1 so that it can be focused
    if (
      elementBefore &&
      (elementBefore.tagName === 'H1' || elementBefore.tagName === 'H2' || elementBefore.tagName === 'H3')
    ) {
      elementBefore.setAttribute('tabindex', '-1')
    }
    elementBefore?.focus()
  }
}

on('click', '.js-flash-close', function (event) {
  const container = event.currentTarget.closest('.flash-messages')

  const dismissButton = event.target as HTMLButtonElement
  focusPreviousElementInDOM(dismissButton)

  const flash = event.currentTarget.closest('.flash')
  flash!.remove()

  if (container && !container.querySelector('.flash')) {
    container.remove()
  }
})

/**
 * Inserts an sr-only span with a non-breaking space into the flash content.
 * The sr-only ensures there are no visual changes.
/** */
export function insertNonBreakingSpace(flashAlertContent: HTMLElement) {
  const nonBreakingSpace = document.createTextNode('\u00A0')
  const span = document.createElement('span')
  span.classList.add('sr-only')
  span.appendChild(nonBreakingSpace)

  flashAlertContent.appendChild(span)
}

/**
 * Contains accessibility logic for server-rendered flash.
 * This JS ensures that the flash content with '.js-flash-alert[role="alert"]' is announced.
 * See: https://github.com/github/accessibility/issues/290
 * Please consult #accessibility if you have any questions.
 */
;(async function () {
  await loaded

  const flashAlertContent: HTMLElement | null = document.querySelector('.js-flash-alert[role="alert"]')
  if (flashAlertContent) {
    // Delay and non-breaking space to ensure that screen readers announce this alert.
    setTimeout(() => {
      insertNonBreakingSpace(flashAlertContent)
    }, 200)
  }
})()

import {displayFlash} from '../flash'
import {observe} from '@github/selector-observer'

observe('template.js-flash-template', {
  constructor: HTMLTemplateElement,
  add(el) {
    displayFlash(el)
  },
})

// Delayed Focus Events
//
// Provides a family cancelable focus/blur that trigger slightly later.
// This makes it easier to build menus that only display when you are
// focused in on a field.
//
// Events
//
// `focusin:delay`
//
// Fired when field is being focused for the first time. Will not fire
// if field is blurred, and refocused in less than 200ms.
//
// * **Synchronicity** Sync
// * **Bubbles** Yes
// * **Cancelable** Yes
// * **Target** Element that is receiving focus.
//
// `focusout:delay`
//
// Fired when field has been blurred for the first time. Won't fire if
// the field is not refocused in under 200ms or the `focusout:delay` is
// canceled.
//
// * **Synchronicity** Sync
// * **Bubbles** Yes
// * **Cancelable** No
// * **Target** Element that is receiving focus.
//
// ```javascript
// on('focusin:delay', function() {
//   showAutocompletions()
// })
//
// on('focusout:delay', function() {
//   hideAutocompletions()
// })
// ```
//

import {fire} from 'delegated-events'

const focused = new WeakMap()

// We use the "focus" and "blur" event in the capture phase because Firefox
// historically had a limitation with "focusin" and "focusout" not bubbling.
document.addEventListener(
  'focus',
  function (event: Event) {
    const target = event.target
    if (target instanceof Element && !focused.get(target)) {
      fire(target, 'focusin:delay')
      focused.set(target, true)
    }
  },
  {capture: true},
)

document.addEventListener(
  'blur',
  function (event: Event) {
    setTimeout(function () {
      const target = event.target
      if (target instanceof Element && target !== document.activeElement) {
        fire(target, 'focusout:delay')
        focused.delete(target)
      }
    }, 200)
  },
  {capture: true},
)

import {announce} from '@github-ui/aria-live'
import {remoteForm} from '@github-ui/remote-form'

remoteForm('.js-form-toggle-target', async function (form, wants) {
  try {
    await wants.text()
  } catch {
    return
  }

  const container = form.closest<HTMLElement>('.js-form-toggle-container')!
  const button = container.querySelector<HTMLElement>('.js-form-toggle-target[hidden]')
  button!.hidden = false
  form.hidden = true
  const feedback = form.getAttribute('data-sr-feedback') || ''
  if (feedback) {
    announce(feedback)
  }
  button?.querySelector<HTMLInputElement>('input[type=submit], button[type=submit]')?.focus()
})

// Find element within document matching location hash.
export function findFragmentTarget(document: Document, hash: string = location.hash): Element | null {
  return findElementByFragmentName(document, decodeFragmentValue(hash))
}

// Find element within document matching id or name.
export function findElementByFragmentName(document: Document, name: string): Element | null {
  if (name === '') return null
  return document.getElementById(name) || document.getElementsByName(name)[0]!
}

// Decode location hash.
export function decodeFragmentValue(hash: string): string {
  try {
    return decodeURIComponent(hash.slice(1))
  } catch {
    return ''
  }
}

import {score as fuzzyScore, hasMatch, positions} from 'fzy.js'

const getScore = (value: string, text: string, minScore: number) => {
  if (!hasMatch(value, text)) return -Infinity
  const score = fuzzyScore(value, text)
  if (score < minScore) return -Infinity
  return score
}
const highlightElement = (node: HTMLElement, value: string, text: string) => {
  node.textContent = ''

  let lastPosition = 0
  for (const i of positions(value, text)) {
    const slice = text.slice(lastPosition, i)
    if (slice !== '') {
      node.appendChild(document.createTextNode(text.slice(lastPosition, i)))
    }
    lastPosition = i + 1
    const mark = document.createElement('mark')
    mark.textContent = text[i]!
    node.appendChild(mark)
  }

  node.appendChild(document.createTextNode(text.slice(lastPosition)))
}

interface sortAbort {
  aborted: boolean
}
const sorting: WeakMap<FuzzyListElement, sortAbort> = new WeakMap()

type FuzzyListLazyRenderCallback = (text: string) => Node
interface state {
  timer: number | null
  handler: MutationObserver
  items: Set<Node>
  lazyItems: Map<string, FuzzyListLazyRenderCallback>
}
const states: WeakMap<FuzzyListElement, state> = new WeakMap()

const textCache: WeakMap<Node, string> = new WeakMap()
const getTextCache = (item: Node) => {
  if (!textCache.has(item) && item instanceof HTMLElement) {
    const value = (item.getAttribute('data-value') || item.textContent || '').trim()
    textCache.set(item, value)
    return value
  }
  return textCache.get(item) || ''
}

class FuzzyListElement extends HTMLElement {
  connectedCallback() {
    /* eslint-disable-next-line wc/no-child-traversal-in-connectedcallback */
    const list = this.querySelector('ul')
    if (!list) return

    const items = new Set(list.querySelectorAll('li'))

    /* eslint-disable-next-line wc/no-child-traversal-in-connectedcallback */
    const inputEl = this.querySelector('input')
    if (inputEl instanceof HTMLInputElement) {
      inputEl.addEventListener('input', () => {
        this.value = inputEl.value
      })
    }

    const handler = new MutationObserver(mutations => {
      let update = false
      for (const mutation of mutations) {
        if (mutation.type === 'childList' && mutation.addedNodes.length) {
          for (const item of mutation.addedNodes) {
            if (item instanceof HTMLLIElement && !items.has(item)) {
              const text = getTextCache(item)
              update = update || hasMatch(this.value, text)
              items.add(item)
            }
          }
        }
      }
      if (update) this.sort()
    })
    handler.observe(list, {childList: true})

    const state = {handler, items, lazyItems: new Map(), timer: null}
    states.set(this, state)
  }

  disconnectedCallback() {
    const state = states.get(this)
    if (state) {
      state.handler.disconnect()
      states.delete(this)
    }
  }

  addLazyItems(dataset: string[], render: FuzzyListLazyRenderCallback) {
    const state = states.get(this)
    if (!state) return
    const {lazyItems} = state
    const {value} = this
    let update = false
    for (const item of dataset) {
      lazyItems.set(item, render)
      update = update || (Boolean(value) && hasMatch(value, item))
    }
    if (update) this.sort()
  }

  sort() {
    const oldSortAbort = sorting.get(this)
    if (oldSortAbort) oldSortAbort.aborted = true
    const sortAbort = {aborted: false}
    sorting.set(this, sortAbort)
    const {minScore, markSelector, maxMatches, value} = this
    const state = states.get(this)
    if (!state) return
    if (!this.dispatchEvent(new CustomEvent('fuzzy-list-will-sort', {cancelable: true, detail: value}))) return
    const {items, lazyItems} = state
    const shouldMark = this.hasAttribute('mark-selector')

    const list = this.querySelector('ul')
    if (!list) return

    const itemsToRender: Array<
      {render: FuzzyListLazyRenderCallback; text: string; score: number} | {item: Node; score: number}
    > = []

    if (value) {
      for (const item of items) {
        const text = getTextCache(item)
        const score = getScore(value, text, minScore)
        if (score === -Infinity) continue
        itemsToRender.push({item, score})
      }
      for (const [text, render] of lazyItems) {
        const score = getScore(value, text, minScore)
        if (score === -Infinity) continue
        itemsToRender.push({text, render, score})
      }
      itemsToRender.sort((a, b) => b.score - a.score).splice(maxMatches)
    } else {
      let i = itemsToRender.length
      for (const item of items) {
        if (i >= maxMatches) break
        itemsToRender.push({item, score: 1})
        i += 1
      }
      for (const [text, render] of lazyItems) {
        if (i >= maxMatches) break
        itemsToRender.push({text, render, score: 1})
        i += 1
      }
    }

    requestAnimationFrame(() => {
      if (sortAbort.aborted) return

      // Store a reference to the checked input (if there is one) as when we
      // append other (stale) items they could be checked, and we want to keep
      // the originally checked item as the only checked item
      const checkedInputBeforeFilter = list.querySelector('input[type="radio"]:checked')

      list.textContent = ''
      let offset = 0

      const nextBatch = () => {
        if (sortAbort.aborted) return
        const end = Math.min(itemsToRender.length, offset + 100)
        const fragment = document.createDocumentFragment()
        for (let i = offset; i < end; i += 1) {
          const itemToRender = itemsToRender[i]!
          let item = null
          if ('render' in itemToRender && 'text' in itemToRender) {
            const {render, text} = itemToRender
            item = render(text)
            items.add(item)
            textCache.set(item, text)
            lazyItems.delete(text)
          } else if ('item' in itemToRender) {
            item = itemToRender.item
          }
          if (item instanceof HTMLElement) {
            if (shouldMark) {
              highlightElement(
                markSelector ? item.querySelector(markSelector) || item : item,
                shouldMark ? value : '',
                getTextCache(item),
              )
            }
            fragment.appendChild(item)
          }
        }
        offset = end

        // Loop through all items that are about to be rendered - if there are
        // any radios that are checked that conflict with the one checked item,
        // then reset them to unchecked state
        let inputStateReset = false
        if (checkedInputBeforeFilter instanceof HTMLInputElement) {
          for (const checkedInput of fragment.querySelectorAll('input[type="radio"]:checked')) {
            if (checkedInput instanceof HTMLInputElement && checkedInput.value !== checkedInputBeforeFilter.value) {
              checkedInput.checked = false
              inputStateReset = true
            }
          }
        }

        if (this.getAttribute('data-tab-only-first')) {
          // Only make first button tabbable, others are navigable by arrow keys
          // https://github.com/github/accessibility-audits/issues/6591
          const buttons = this.querySelectorAll('button.js-emoji-button')
          for (const button of buttons) {
            button.setAttribute('tabindex', '-1')
          }
          buttons.item(0)?.setAttribute('tabindex', '0')
        } else {
          // Make sure that the fragments we're appending are accessible by 'tab'
          for (const button of fragment.querySelectorAll('button[tabindex="-1"]')) {
            button.setAttribute('tabindex', '0')
          }
        }

        list.appendChild(fragment)

        // If any checked items were changed then a change event should be
        // fired to let other observers know
        if (checkedInputBeforeFilter && inputStateReset) {
          checkedInputBeforeFilter.dispatchEvent(new Event('change', {bubbles: true}))
        }

        if (end < itemsToRender.length) {
          requestAnimationFrame(nextBatch)
        } else {
          list.hidden = itemsToRender.length === 0
          const emptyEl = this.querySelector<HTMLElement>('[data-fuzzy-list-show-on-empty]')
          if (emptyEl) {
            emptyEl.hidden = itemsToRender.length > 0
          }

          this.dispatchEvent(new CustomEvent('fuzzy-list-sorted', {detail: itemsToRender.length}))
        }
      }

      nextBatch()
    })
  }

  get value(): string {
    return this.getAttribute('value') || ''
  }

  set value(value: string) {
    this.setAttribute('value', value)
  }

  get markSelector(): string {
    return this.getAttribute('mark-selector') || ''
  }

  set markSelector(value: string) {
    if (value) {
      this.setAttribute('mark-selector', value)
    } else {
      this.removeAttribute('mark-selector')
    }
  }

  get minScore(): number {
    return Number(this.getAttribute('min-score') || 0)
  }

  set minScore(value: number) {
    if (Number.isNaN(value)) return
    this.setAttribute('min-score', String(value))
  }

  get maxMatches(): number {
    return Number(this.getAttribute('max-matches') || Infinity)
  }

  set maxMatches(value: number) {
    if (Number.isNaN(value)) return
    this.setAttribute('max-matches', String(value))
  }

  get ariaLiveElement(): HTMLElement | undefined {
    const targetId = this.getAttribute('data-aria-live-element')
    if (!targetId) return

    const element = document.getElementById(targetId)
    if (!element) return

    return element
  }

  static get observedAttributes(): string[] {
    return ['value', 'mark-selector', 'min-score', 'max-matches']
  }

  attributeChangedCallback(name: string, oldValue: string, newValue: string) {
    if (oldValue === newValue) return
    const state = states.get(this)
    if (!state) return
    if (state.timer) window.clearTimeout(state.timer)
    state.timer = window.setTimeout(() => this.sort(), 100)
  }
}

