// Example:
//
//    <div class="js-line-comments">
//      <div class="js-inline-comment-form-container">
//        <button class="js-toggle-inline-comment-form">
//        <form>
//          <texarea class="js-comment-field"></textarea>
//          <button class="js-hide-inline-comment-form">Cancel</button>
//        </form>
//      </div>
//    </div>

import {fire, on} from 'delegated-events'
import {hasDirtyFields} from '@github-ui/has-interactions'
import {onKey} from '@github-ui/onfocus'

// "Add a line note" button
//
// Hide self and show form.
on('click', '.js-toggle-inline-comment-form', function (event) {
  const comments = event.currentTarget.closest<HTMLElement>('.js-line-comments')!
  focusForm(comments)
})

// With a line comment selected, hitting "r" focuses the form with the quoted
// text.
on('quote-selection', '.js-line-comments', function (event) {
  focusForm(event.currentTarget)
  event.stopPropagation()
})

// Install handlers on inline note comment form focusin
onKey('keydown', '.js-inline-comment-form-container form .js-comment-field', function (event: KeyboardEvent) {
  // TODO: Refactor to use data-hotkey
  /* eslint eslint-comments/no-use: off */
  /* eslint-disable @github-ui/ui-commands/no-manual-shortcut-logic */
  const field = event.target as HTMLTextAreaElement

  if (field.classList.contains('js-navigation-enable')) {
    return
  }

  if (event.key === 'Escape' && field.value.length === 0) {
    const form = field.closest<HTMLFormElement>('form')!
    blurForm(form)
    event.preventDefault()
  }
  /* eslint-enable @github-ui/ui-commands/no-manual-shortcut-logic */
})

// "Close form" button
//
// Hide self and show "Add a line button" again. If theres no comments cleanup
// the empty container.
on('click', '.js-hide-inline-comment-form', function (event) {
  const form = event.currentTarget.closest<HTMLFormElement>('form')!

  if (!hasDirtyFields(form) || confirm((event.currentTarget as Element).getAttribute('data-confirm-cancel-text')!)) {
    blurForm(form)
  } else {
    // Do not reset form
    event.preventDefault()
  }
})

// Opens form container, ensures write tab is selected and focuses textarea.
export function focusForm(comments: Element) {
  const container = comments.querySelector<HTMLElement>('.js-inline-comment-form-container')!
  container.classList.add('open')
  container.querySelector<HTMLElement>('.js-write-tab')?.click()
  container.querySelector<HTMLElement>('.js-comment-field')!.focus()
  fire(container, 'inlinecomment:focus')
}

// Reset and close comment form. Opposite of focusForm.
// Hide multi-line-preview (range info).
//
// form - A .js-inline-comment-form HTMLFormElement
export function blurForm(form: HTMLFormElement) {
  form.reset()

  const container = form.closest<HTMLElement>('.js-inline-comment-form-container')!
  container.classList.remove('open')

  const multiLinePreview = container.querySelector<HTMLElement>('.js-multi-line-preview')
  if (multiLinePreview) {
    multiLinePreview.hidden = true
  }

  fire(container, 'inlinecomment:collapse')
}

import type {QueryEvent, SearchProvider, SearchScopeText} from '@github-ui/query-builder-element/query-builder-api'
import {Octicon, SearchItem} from '@github-ui/query-builder-element/query-builder-api'
import type {QueryBuilderElement} from '@github-ui/query-builder-element'
import type {ParsedIntermediateRepresentation} from '../qbsearch-input-element'
import type {QualifierNode, NodeWithChildren, ContentNode} from '@github/blackbird-parser'
import {CaretPositionKind, extractRepoOrgScopes, hasChildren, isQualifier} from '../parsing/common'
// eslint-disable-next-line import/no-namespace
import type * as Parsing from '../parsing/parsing'

export class InputProvider extends EventTarget implements SearchProvider {
  priority = 0
  name = ''
  singularItemName = 'search'
  value = 'search'
  type = 'search' as const
  copilotChatEnabled: boolean = false
  #input: HTMLElement
  #parser: typeof Parsing | undefined

  queryBuilder: QueryBuilderElement

  constructor(queryBuilder: QueryBuilderElement, input: HTMLElement) {
    super()
    this.queryBuilder = queryBuilder
    this.queryBuilder.addEventListener('query', this)
    this.#input = input
  }

  async handleEvent(event: QueryEvent) {
    const state = event.parsedMetadata as ParsedIntermediateRepresentation | undefined

    if (event.rawQuery) {
      // Always emit a fallback suggestion, if no other suggestions exist
      this.dispatchEvent(
        new SearchItem({
          value: event.rawQuery,
          scope: 'GITHUB',
          icon: Octicon.Search,
          priority: 0,
          action: {
            query: event.rawQuery,
          },
          isFallbackSuggestion: true,
        }),
      )
    }

    if (!state || state.caretPositionKind !== CaretPositionKind.Text) {
      return []
    }

    let trimmedQuery = state.query.trim()

    let repo = this.#input.getAttribute('data-current-repository')
    let org = this.#input.getAttribute('data-current-org')
    let orgNode: QualifierNode | undefined = undefined
    let user = this.#input.getAttribute('data-current-owner')
    let business = this.#input.getAttribute('data-current-business')

    if (!this.#parser) {
      this.#parser = await import('../parsing/parsing')
    }

    // Use query to extract the current qualifier for suggestions
    const astNode: NodeWithChildren = this.#parser.parseString(trimmedQuery || '') as NodeWithChildren

    // No qualifiers found
    if (astNode.children) {
      const qualifierNodes = astNode.children.filter(node => node.kind === 'Qualifier')
      repo = (qualifierNodes.find(node => node.qualifier === 'Repo')?.content as ContentNode)?.value?.toString() || repo
      orgNode = qualifierNodes.find(node => node.qualifier === 'Org')
      org = (orgNode?.content as ContentNode)?.value?.toString() || org
      user =
        (
          qualifierNodes.find(node => node.qualifier === 'Org' && node.raw === 'user:')?.content as ContentNode
        )?.value?.toString() || user
      business =
        (qualifierNodes.find(node => node.qualifier === 'Enterprise')?.content as ContentNode)?.value?.toString() ||
        business
      // Get owner from nwo
      if (repo && !orgNode) {
        org = repo.split('/')[0]!
      }
    }

    interface Suggestion {
      query: string
      scope?: keyof typeof SearchScopeText
    }
    const suggestions: Suggestion[] = []
    let containsScopes = false

    if (state.ast) {
      const node = state.ast

      // check if node has query text attached to it (not just qualifier)
      if (hasChildren(node)) {
        trimmedQuery = node.children
          .filter(item => item.kind === 'Text')
          .map(item => item.value)
          .join(' ')

        const scopes = extractRepoOrgScopes(node)
        // If the scopes contains a saved scope, don't generate input suggestions,
        // since we can't generate sensible parent scopes.
        if (scopes.find(s => s.kind === 'saved')) {
          return []
        }

        // If text has a repo or org qualifier within it, show just query text at the bottom of input
        if (scopes.length) {
          containsScopes = true
        }
      } else if (isQualifier(node)) {
        // if node is only a qualifier, don't include it as part of query text
        trimmedQuery = ''
      }

      if (repo && repo.length > 0) {
        suggestions.push({
          query: `repo:${repo} ${trimmedQuery}`,
          scope: 'REPO',
        })
      }
      if (orgNode) {
        suggestions.push({
          query: `${orgNode.raw}${org} ${trimmedQuery}`,
          scope: 'ORG',
        })
      } else {
        if (org && org.length > 0) {
          suggestions.push({
            query: `org:${org} ${trimmedQuery}`,
            scope: 'ORG',
          })
        }
        if (user && user.length > 0) {
          suggestions.push({
            query: `user:${user} ${trimmedQuery}`,
            scope: 'OWNER',
          })
        }
      }
      if (business && business.length > 0) {
        suggestions.push({
          query: `enterprise:${business} ${trimmedQuery}`,
          scope: 'ENTERPRISE',
        })
      }
    }

    if (trimmedQuery.length > 0) {
      if (!containsScopes) {
        suggestions.unshift({
          query: trimmedQuery,
          scope: 'GITHUB',
        })
      } else {
        suggestions.push({query: trimmedQuery, scope: 'GITHUB'})
      }
    }

    // If we are currently on a non-root tree view page, offer to search within
    // the current directory.
    const path = getPathQualifier(window.location.pathname)
    if (path) {
      const query = `repo:${repo} path:${path} ${trimmedQuery}`
      this.dispatchEvent(
        new SearchItem({
          value: query,
          scope: 'DIRECTORY',
          icon: Octicon.Search,
          priority: 0,
          action: {
            commandName: 'blackbird-monolith.search',
            data: {
              query,
            },
          },
        }),
      )
    }

    for (const suggestion of suggestions.slice(0, 3)) {
      this.dispatchEvent(
        new SearchItem({
          value: suggestion.query,
          scope: suggestion.scope,
          icon: Octicon.Search,
          priority: 0,
          action: {
            commandName: 'blackbird-monolith.search',
            data: {
              query: suggestion.query,
            },
          },
        }),
      )
    }
  }

  getQualifierType(input: string): string {
    if (input.includes('repo')) {
      // eslint-disable-next-line i18n-text/no-en
      return 'In this repository'
    } else if (input.includes('org')) {
      // eslint-disable-next-line i18n-text/no-en
      return 'In this organization'
    } else if (input.includes('user')) {
      // eslint-disable-next-line i18n-text/no-en
      return 'In this user'
    } else if (input.includes('owner')) {
      // eslint-disable-next-line i18n-text/no-en
      return 'In this owner'
    } else if (input.includes('enterprise')) {
      // eslint-disable-next-line i18n-text/no-en
      return 'In this enterprise'
    } else {
      // eslint-disable-next-line i18n-text/no-en
      return 'All of GitHub'
    }
  }
}

function buildRegexQuery(path: string): string {
  // Decode any URL characters
  path = decodeURIComponent(path)

  // Strip trailing slash
  if (path.endsWith('/')) {
    path = path.substring(0, path.length - 1)
  }

  // Escape regex chars
  const escaped = path.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')

  // Build path regex query
  return `/^${escaped.replaceAll('/', '\\/')}\\//`
}

export function getPathQualifier(pathname: string): string | undefined {
  const treeRegex = /^\/[^/]+\/[^/]+\/tree\/[^/]+\/(.*)/

  const m = treeRegex.exec(pathname)
  if (m) {
    for (let i = 1; i < m.length; i++) {
      if (m[i]) {
        return buildRegexQuery(m[i]!)
      }
    }
  }

  return undefined
}

import {controller, target, targets} from '@github/catalyst'

// Demultiplexes InputEvents on an <input> for use with multiple
// elements in a <tab-container>.  Also provides notifications to
// tabpanels when they are opened.
//
// On input, element corresponding to the selected tab gets a `input-entered`
// event with its `detail` property set to the current value of the input.
// Also performs similar proxying of mouseover events from an optional
// enclosing details element to the "primary" tab so it can e.g. prefetch data.
@controller('input-demux')
class InputDemuxElement extends HTMLElement {
  // The <input> element to be shared among our sinks
  @target declare source: HTMLInputElement

  // The elements we are selecting among
  @targets declare sinks: HTMLElement[]

  // Determines which sink is selected by its children's aria-selected
  // attributes.  Probably a role="tablist" with children of role="tab"
  @target declare control: HTMLElement

  // Temporary store for input values while other tabs are using the <input>.
  declare storedInput: string[]

  connectedCallback() {
    if (this.control) this.storedInput = Array(this.control.children.length).fill('')
    this.addEventListener('input', this.relayInput.bind(this))
    this.addEventListener('keydown', this.relayKeydown.bind(this))
    const details = this.closest('details')
    if (details) {
      details.addEventListener('toggle', () => {
        // Move the cursor to the input after the details menu is opened.
        // This is especially nice in combination with the 'w' shortcut!
        if (details.open) {
          this.source.focus()
        }
      })
    }
  }

  // Invoked on keydown to emulate the existing behavior where pressing down
  // when the input is focused should focus the first list item.
  relayKeydown(e: KeyboardEvent) {
    // TODO: Refactor to use data-hotkey
    /* eslint eslint-comments/no-use: off */
    /* eslint-disable @github-ui/ui-commands/no-manual-shortcut-logic */
    if ((this.isControlTab(e.target) || e.target === this.source) && (e.key === 'ArrowDown' || e.key === 'Tab')) {
      e.preventDefault()
      e.stopPropagation()
      this.routeCustomEvent(new CustomEvent('focus-list'))
    } else if (e.key === 'Escape') {
      const details = this.closest('details')
      if (details) {
        details.removeAttribute('open')
      }
    }
    /* eslint-enable @github-ui/ui-commands/no-manual-shortcut-logic */
  }

  // Is the given EventTarget one of our control tabs?
  isControlTab(element: EventTarget | null): boolean {
    if (!element) return false
    if (!this.control) return false
    return Array.from(this.control.children).includes(element as Element)
  }

  // Invoked on input.  Decide which sink is selected and dispatch a
  // CustomEvent that either contains input or a mouseover notification.
  relayInput(e: Event) {
    if (!e.target) return
    const eventTarget = e.target as HTMLElement
    const text = (eventTarget as HTMLInputElement).value
    this.routeCustomEvent(new CustomEvent('input-entered', {detail: text}))
  }

  // Dispatch an event on whichever sink is currently selected.
  routeCustomEvent(event: Event) {
    const sink = this.sinks[this.selectedIndex]!
    sink.dispatchEvent(event)
  }

  // The index of the selected tab.
  get selectedIndex() {
    if (!this.control) return 0
    const selected = this.control.querySelector('[aria-selected="true"]')
    if (!selected) return 0
    return Array.from(this.control.children).indexOf(selected)
  }

  // Save the input value before switching tabs.
  storeInput() {
    this.storedInput[this.selectedIndex] = this.source.value
  }

  // Restore a stored input value after switching tabs.
  updateInput(e: CustomEvent) {
    this.source.value = this.storedInput[this.selectedIndex]!
    const placeholder = e.detail.relatedTarget.getAttribute('data-filter-placeholder')
    this.source.placeholder = placeholder
    this.source.setAttribute('aria-label', placeholder)
    this.notifySelected()
  }

  // Courtesy notification to the element whose tab was just selected
  notifySelected() {
    const sink = this.sinks[this.selectedIndex]!
    const event = new CustomEvent('tab-selected')
    sink.dispatchEvent(event)
  }
}

import {controller} from '@github/catalyst'
import {dialog} from '@github-ui/details-dialog'

interface InputDemuxContext {
  onItemSelected(event: MouseEvent): void
}

interface ContextMap {
  baseChange: InputDemuxContext
}

class InputDemuxBaseChangeContext implements InputDemuxContext {
  onItemSelected(event: MouseEvent) {
    if (!(event.currentTarget instanceof HTMLButtonElement)) return
    const selectedRef = event.currentTarget.querySelector<HTMLSpanElement>('.js-ref-name')!.textContent
    const input = document.querySelector<HTMLInputElement>('.js-new-base-branch')!
    input.value = btoa(unescape(encodeURIComponent(selectedRef || '')))

    const content = document.querySelector<HTMLTemplateElement>('.js-change-base-template')!.content.cloneNode(true)
    if (!(content instanceof DocumentFragment)) return
    dialog({content})
  }
}

@controller('input-demux-context-wrapper')
class InputDemuxContextWrapperElement extends HTMLElement {
  declare context: InputDemuxContext

  connectedCallback() {
    const contextType = this.getAttribute('data-context-type')
    const contexts: ContextMap = {baseChange: new InputDemuxBaseChangeContext()}
    this.context = contexts[contextType as keyof ContextMap]
  }

  /* eslint-disable-next-line wc/no-method-prefixed-with-on */
  onItemSelected(event: MouseEvent) {
    this.context.onItemSelected(event)
  }
}

import {controller} from '@github/catalyst'
import {eventToHotkeyString} from '@github-ui/hotkey'
import {sendHydroEvent} from '../../github/hydro-tracking'

// Track CTRL+F usage on Files changed tab
// to determine the cost of virtualizing the list of patches
@controller('instrument-files')
class InstrumentFilesElement extends HTMLElement {
  connectedCallback() {
    document.addEventListener('keydown', this.instrumentCtrlF)
  }

  disconnectedCallback() {
    document.removeEventListener('keydown', this.instrumentCtrlF)
  }

  instrumentCtrlF = (event: KeyboardEvent) => {
    const findCommands = ['Control+f', 'Meta+f']
    const hotkeyString = eventToHotkeyString(event)
    if (findCommands.includes(hotkeyString)) {
      sendHydroEvent(this)
    }
  }
}

/**
 * This file contains main window commands for issues.
 *
 * To add another command, define a new subclass and append the
 * class to the default export at the bottom of the file.
 */
import {MainWindowCommand} from '../main-window-command'
import type {ModalDialogElement} from '@primer/view-components/app/components/primer/alpha/modal_dialog'
import {isFeatureEnabled} from '@github-ui/feature-flags'

function moveCursorToEnd(input: HTMLTextAreaElement | HTMLInputElement) {
  input.focus()
  input.selectionStart = input.selectionEnd = input.value.length
}

export class EditIssueBody extends MainWindowCommand {
  override title = 'Edit issue body'
  override icon = 'pencil-color-fg-muted'

  issueBody() {
    return document.querySelector('.js-command-palette-issue-body')
  }

  isIssue() {
    return !!this.issueBody()
  }

  override isApplicable() {
    return this.isIssue()
  }

  override run() {
    // Build an edit button (the normal one isn't always loaded)
    const editButton = document.createElement('button')
    editButton.hidden = true
    editButton.classList.add('js-comment-edit-button')

    const issueBody = document.querySelector('div.js-comment')
    issueBody?.appendChild(editButton)

    editButton.click()
    editButton.remove()

    setTimeout(() => {
      const textArea = issueBody?.parentElement?.querySelector<HTMLTextAreaElement>('textarea.js-comment-field')

      if (textArea) {
        moveCursorToEnd(textArea)
      }
    }, 0)
  }
}

export class EditIssueTitle extends MainWindowCommand {
  override title = 'Edit issue title'
  override icon = 'pencil-color-fg-muted'

  issueBody() {
    return document.querySelector('.js-command-palette-issue-body')
  }

  isIssue() {
    return !!this.issueBody()
  }

  override isApplicable() {
    return this.fetchButton() instanceof HTMLButtonElement && this.isIssue()
  }

  fetchButton() {
    return document.querySelector<HTMLButtonElement>('.js-title-edit-button')
  }

  override run() {
    this.fetchButton()?.click()

    // Even though the input has an autofocus, it isn't focused when it is unhidden.
    setTimeout(() => {
      const input = document.querySelector<HTMLInputElement>('input#issue_title[autofocus]')

      if (input) {
        moveCursorToEnd(input)
      }
    }, 0)
  }
}

export class AddTasklist extends MainWindowCommand {
  override title = 'Add tasklist to issue'
  override icon = 'plus-circle-color-fg-muted'

  issueBody() {
    return document.querySelector('.js-command-palette-issue-body')
  }

  isIssue() {
    return !!this.issueBody()
  }

  override isApplicable() {
    return isFeatureEnabled('tasklist_block') && this.isIssue()
  }

  override run() {
    // Build an edit button (the normal one isn't always loaded)
    const editButton = document.createElement('button')
    editButton.hidden = true
    editButton.classList.add('js-comment-edit-button')

    const issueBody = document.querySelector('div.js-comment')
    issueBody?.appendChild(editButton)

    editButton.click()
    editButton.remove()

    setTimeout(() => {
      const textArea = issueBody?.parentElement?.querySelector<HTMLTextAreaElement>('textarea.js-comment-field')

      if (textArea) {
        let tasklistMarkup = document.createTextNode(
          '```[tasklist]\n- [ ] Create a draft issue or type # to select an issue\n```',
        )
        if (textArea.value !== '') {
          tasklistMarkup = document.createTextNode(
            '\n\n```[tasklist]\n- [ ] Create a draft issue or type # to select an issue\n```',
          )
        }
        moveCursorToEnd(textArea)
        textArea?.appendChild(tasklistMarkup)
      }
    }, 0)
  }
}

class TransferIssue extends MainWindowCommand {
  override title = 'Transfer issue…'
  override icon = 'arrow-right-color-fg-muted'

  override isApplicable() {
    return this.fetchDetails() instanceof HTMLDetailsElement
  }

  fetchDetails() {
    return document.querySelector<HTMLDetailsElement>('details.js-transfer-issue')
  }

  override run() {
    const transferIssueDetails = this.fetchDetails()

    if (transferIssueDetails) {
      const focusMenu = () => {
        setTimeout(() => {
          transferIssueDetails.querySelector<HTMLElement>('[data-menu-button]')?.focus()
        }, 0)
      }

      transferIssueDetails.querySelector<HTMLElement>('include-fragment')?.addEventListener('load', focusMenu)

      transferIssueDetails.open = true
      focusMenu()
    }
  }
}

class LockIssue extends MainWindowCommand {
  constructor() {
    super()
    const isLockCommand = this.isLock()
    this.title = `${isLockCommand ? 'Lock' : 'Unlock'} conversation`
    this.icon = `${isLockCommand ? 'lock' : 'key'}-color-fg-muted`
  }

  override isApplicable() {
    return this.fetchDetails() instanceof HTMLDetailsElement
  }

  isLock() {
    return document.querySelector('summary.lock-toggle-link')?.textContent?.trim() === 'Lock conversation'
  }

  fetchDetails() {
    return document.querySelector<HTMLDetailsElement>('details.js-lock-issue')
  }

  override run() {
    const lockIssueDetails = this.fetchDetails()
    if (lockIssueDetails) {
      lockIssueDetails.open = true

      setTimeout(() => {
        document.querySelector<HTMLSelectElement>('#unlock-reason')?.focus()
      }, 0)
    }
  }
}

class DeleteIssue extends MainWindowCommand {
  override title = 'Delete issue…'
  override icon = 'trash-color-fg-muted'

  override isApplicable() {
    return this.fetchDetails() instanceof HTMLDetailsElement
  }

  fetchDetails() {
    return document.querySelector<HTMLDetailsElement>('details.js-delete-issue')
  }

  override run() {
    const deleteIssueDetails = this.fetchDetails()
    if (deleteIssueDetails) {
      deleteIssueDetails.open = true

      setTimeout(() => {
        deleteIssueDetails.querySelector<HTMLButtonElement>('button[type="submit"]')?.focus()
      }, 0)
    }
  }
}

export class ConvertToDiscussion extends MainWindowCommand {
  override title = 'Convert issue to discussion…'
  override icon = 'comment-discussion-color-fg-muted'

  override isApplicable() {
    return this.fetchConvertButton() instanceof HTMLButtonElement
  }

  fetchConvertButton() {
    return document.querySelector<HTMLButtonElement>('button#dialog-show-convert-to-discussion')
  }

  fetchDialog() {
    return document.querySelector<ModalDialogElement | HTMLDialogElement>('#convert-to-discussion')
  }

  override run() {
    const convertToDiscussionButton = this.fetchConvertButton()
    const convertToDiscussionDialog = this.fetchDialog()
    if (convertToDiscussionButton && convertToDiscussionDialog) {
      const focusMenu = () => {
        setTimeout(() => {
          convertToDiscussionDialog?.querySelector<HTMLElement>('#convert-to-discussion-category')?.focus()
        }, 0)
      }

      convertToDiscussionDialog.querySelector<HTMLElement>('include-fragment')?.addEventListener('load', focusMenu)
      if (convertToDiscussionDialog instanceof HTMLDialogElement) {
        convertToDiscussionDialog.showModal()
      } else {
        convertToDiscussionDialog.open = true
      }
      focusMenu()
    }
  }
}

export default [EditIssueTitle, EditIssueBody, AddTasklist, LockIssue, TransferIssue, DeleteIssue, ConvertToDiscussion]

import {fromEvent} from '@github-ui/subscription'
import {observe} from '@github/selector-observer'
import {getBaseFetchHeaders} from '@github-ui/fetch-headers'

// Load issue/PR/discussion references to display the title for the tooltip from the server on hover.
// If hovercards are enabled for the referenced type on this part of the DOM,
// this behavior is bypassed in favor of the hovercard.
async function issueLabel(event: Event) {
  const currentTarget = event.currentTarget as HTMLElement
  const url = currentTarget.getAttribute('data-url')
  if (!url || isHovercardEnabled(currentTarget)) {
    return
  }

  const id = currentTarget.getAttribute('data-id') || ''
  const text = currentTarget.textContent
  const elements = document.querySelectorAll(`.js-issue-link[data-id='${id}']`)

  for (const el of elements) {
    el.removeAttribute('data-url')
  }

  try {
    const titleUrl = `${url}/title`
    const response = await fetch(titleUrl, {
      headers: {
        ...getBaseFetchHeaders(),
        Accept: 'application/json',
      },
    })
    if (!response.ok) {
      const responseError = new Error()
      const statusText = response.statusText ? ` ${response.statusText}` : ''
      responseError.message = `HTTP ${response.status}${statusText}`
      throw responseError
    }
    const data = await response.json()
    setLabel(elements, `${text}, ${data.title}`)
  } catch (error) {
    // @ts-expect-error catch blocks are bound to `unknown` so we need to validate the type before using it
    const status = (error.response != null ? error.response.status : undefined) || 500

    const message = (() => {
      switch (status) {
        case 404:
          return currentTarget.getAttribute('data-permission-text')
        default:
          return currentTarget.getAttribute('data-error-text')
      }
    })()

    setLabel(elements, message || '')
  }
}

function setLabel(elements: NodeList, text: string) {
  for (const el of elements) {
    if (!(el instanceof HTMLElement)) continue
    el.classList.add('tooltipped', 'tooltipped-ne')
    el.setAttribute('aria-label', text)
  }
}

function isHovercardEnabled(element: HTMLElement): boolean {
  const hovercardType = element.getAttribute('data-hovercard-type')
  switch (hovercardType) {
    case 'issue':
    case 'pull_request':
      return !!element.closest('[data-issue-and-pr-hovercards-enabled]')
    case 'discussion':
      return !!element.closest('[data-discussion-hovercards-enabled]')
    default:
      return false
  }
}

observe('.js-issue-link', {
  subscribe: el => fromEvent(el, 'mouseenter', issueLabel),
})

import type CommandPalette from '../command-palette-element'
import {isPlatformMetaKey} from '../command-palette-element'
import {type ServerDefinedAction, ServerDefinedItem, serverDefinedItem} from './server-defined-item'

interface JumpToAction extends ServerDefinedAction {
  path: string
}

interface JumpToItemArguments {
  title: string
  icon: string
  path: string
  group: string
}

@serverDefinedItem('jump_to')
export class JumpToItem extends ServerDefinedItem {
  declare _action: JumpToAction

  static from(args: JumpToItemArguments) {
    return new JumpToItem({
      title: args.title,
      typeahead: args.title,
      priority: 1,
      score: 1,
      group: args.group,
      action: {
        type: 'jump_to',
        description: '',
        path: args.path,
      },
      icon: {
        type: 'octicon',
        id: args.icon,
      },
    })
  }

  override activate(_commandPalette: CommandPalette, event: Event) {
    // activate can be called by either an onKeydown event or a mouse click. If it's a mouse click, we don't need to do
    // anything special, just call the super method to makes sure everything that needs to happen does. If it's an onKeydown event,
    // then we can trigger the normal link activation, which calls a click event on the item, which brings us right back here
    // for the click trigger.
    // we need to only call one or the other so we don't send two tracking events.
    if (event instanceof PointerEvent) {
      super.activate(_commandPalette, event)
    } else if (event instanceof KeyboardEvent) {
      this.activateLinkBehavior(_commandPalette, event, isPlatformMetaKey(event))
    }
  }

  override copy(commandPalette: CommandPalette) {
    super.copy(commandPalette)

    const url = new URL(this.action.path, window.location.origin)

    this.copyToClipboardAndAnnounce(url.toString())
    return url.toString()
  }

  override get key() {
    return `${super.key}/${this.action.path}`
  }

  override get action() {
    return this._action
  }
}

