import {attr, controller} from '@github/catalyst'
import {updateContent} from '@github-ui/updatable-content'
import {getStoredShelfParamsForCurrentPage} from '../../assets/modules/github/notifications/v2/notification-shelf-referrer-params'
import {throttle} from '@github/mini-throttle'

/**
 * NotificationShelfWatcherElement
 * This element will load the notification top shelf bar asynchronously to reduce the page dependency with notifications clusters
 * It will also listen to channel updates to update the form. This is done because some notifications are marked as read asynchronously
 * which means the form might not have the latest data on first load
 */
@controller('notification-shelf-watcher')
export class NotificationShelfWatcherElement extends HTMLElement {
  @attr declare baseUrl: string
  @attr refreshDelay = 500 // ms
  @attr throttleDelay = 5_000 // ms

  declare src: string | void
  declare timeout: ReturnType<typeof setTimeout> | void

  declare hasUpdatedWhileHidden: boolean // true if we received an update while the tab was hidden

  connectedCallback() {
    this.preload()
    this.update()

    const callback = throttle(this.update.bind(this), this.throttleDelay)
    this.addEventListener('socket:message', callback)

    // Subscribe to visibility changes to only update when the tab is active
    document.addEventListener('visibilitychange', this.visibilityCallback.bind(this))
  }

  visibilityCallback() {
    if (this.hasUpdatedWhileHidden && document.visibilityState === 'visible') {
      this.update()
      this.hasUpdatedWhileHidden = false
    }
  }

  preload() {
    this.src = this.preloadSrc()
  }

  preloadSrc(): string {
    const src = this.getAttribute('src')
    if (src && src !== '') {
      const link = this.ownerDocument.createElement('a')
      link.href = src
      return link.href
    }

    // Try to load the src from the storage
    // This is useful for when the page is reloaded and it doesn't have the notification_referrer_id in the URL
    // anymore because it was removed on first load
    if (!this.baseUrl) {
      return ''
    }

    const params = getStoredShelfParamsForCurrentPage()
    if (!params) {
      return ''
    }

    const shelfURL = new URL(this.baseUrl, window.location.origin)
    const searchParams = new URLSearchParams(shelfURL.search)

    for (const [key, value] of Object.entries(params)) {
      if (typeof value === 'string') {
        searchParams.set(key, value)
      }
    }
    shelfURL.search = searchParams.toString()

    return shelfURL.toString()
  }

  async update() {
    if (document.visibilityState === 'hidden') {
      // Tab is inactive, so queue the update for when the tab becomes visible
      this.hasUpdatedWhileHidden = true
      return
    }

    if (this.timeout) {
      clearTimeout(this.timeout)
    }

    if (!this.src || this.src === '') {
      return
    }

    const el = this.placeholder()
    if (!el) {
      return
    }

    const isInitial = el.hasAttribute('data-initial')

    el.setAttribute('data-url', this.src)
    await updateContent(el)

    if (isInitial) {
      this.refresh()
    }
  }

  placeholder(): HTMLElement | null {
    return document.querySelector<HTMLElement>("[data-target='notification-shelf-watcher.placeholder']")
  }

  refresh() {
    const el = this.placeholder()
    if (!el) {
      return
    }

    const inner = el.querySelector("[data-notification-status='unread']")

    // First time loading and the content is shown as unread. This could be because the
    // `mark_as_read` action in the controller was delayed. Try to fetch it again.
    if (inner) {
      this.timeout = setTimeout(() => this.update(), this.refreshDelay)
    }
  }
}

import type {
  NotificationsDialogLabelItemElement,
  NotificationsDialogLabelToggledEvent,
} from './notifications-subscriptions-dialog-label-item'
import {controller, target, targets} from '@github/catalyst'
import {hideGlobalError, showGlobalError} from '../behaviors/ajax-error'
import type DetailsDialogElement from '@github/details-dialog-element'
import type DetailsMenuElement from '@github/details-menu-element'
import {changeValue} from '@github-ui/form-utils'
import {getBaseFetchHeaders} from '@github-ui/fetch-headers'

@controller('notifications-list-subscription-form')
class NotificationsListSubscriptionFormElement extends HTMLElement {
  @target declare details: HTMLDetailsElement
  @target declare menu: DetailsMenuElement
  @target declare customButton: HTMLButtonElement
  @target declare customDialog: DetailsDialogElement
  @target declare filterLabelsDialog: DetailsDialogElement
  @targets declare subscriptionButtons: HTMLButtonElement[]
  @targets declare subscriptionsLabels: HTMLElement[]
  @target declare labelInputs: HTMLElement
  @target declare subscriptionsSubtitle: HTMLElement
  @target declare socialCount: HTMLElement
  @target declare unwatchButtonCopy: HTMLElement
  @target declare stopIgnoringButtonCopy: HTMLElement
  @target declare watchButtonCopy: HTMLElement
  @targets declare threadTypeCheckboxes: HTMLInputElement[]
  @target declare customSubmit: HTMLButtonElement
  @target declare subscriptionsContainer: HTMLElement
  @targets declare dialogLabelItems: NotificationsDialogLabelItemElement[]

  lastAppliedLabels: {[labelId: string]: Node} = {}

  async submitCustomForm(e: Event) {
    await this.submitForm(e)
    this.closeMenu()
  }

  async submitForm(e: Event) {
    e.preventDefault()

    hideGlobalError()

    const form = e.currentTarget as HTMLFormElement
    const body = new FormData(form)

    const response = await self.fetch(form.action, {
      method: form.method,
      body,
      headers: {
        ...getBaseFetchHeaders(),
        Accept: 'application/json',
      },
    })

    if (!response.ok) {
      showGlobalError()
      return
    }
    const json = await response.json()

    const doParam = body.get('do')
    if (typeof doParam === 'string') this.updateCheckedState(doParam)
    if (typeof doParam === 'string') this.updateMenuButtonCopy(doParam)
    this.updateSocialCount(json.count)
    this.applyInputsCheckedPropertiesToAttributesForNextFormReset()
    this.closeMenu()
  }

  updateMenuButtonCopy(subscription: string) {
    this.unwatchButtonCopy.hidden = !(subscription === 'subscribed' || subscription === 'custom')
    this.stopIgnoringButtonCopy.hidden = !(subscription === 'ignore')
    this.watchButtonCopy.hidden = !(
      subscription !== 'subscribed' &&
      subscription !== 'custom' &&
      subscription !== 'ignore'
    )
  }

  // form.reset() will reset the form back to the values in it's html attributes, not to it's current JS properties
  // therefore, after successfully saving the form to the server, we transfer value of the `.checked` properties
  // of the inputs in the form into the `[checked]` attribute. This means that if the user reopens the form and
  // edits it again, cancelling will reset the form to it's last saved state, not the original state on page load
  applyInputsCheckedPropertiesToAttributesForNextFormReset() {
    for (const input of [...this.threadTypeCheckboxes]) {
      input.toggleAttribute('checked', input.checked)
    }
  }

  updateCheckedState(doParam: string) {
    for (const button of this.subscriptionButtons) {
      button.setAttribute('aria-checked', button.value === doParam ? 'true' : 'false')
    }

    if (doParam === 'custom') {
      this.customButton.setAttribute('aria-checked', 'true')
    } else {
      this.customButton.setAttribute('aria-checked', 'false')

      for (const input of [...this.threadTypeCheckboxes]) {
        changeValue(input, false)
      }
      // Clean up labels
      if (this.subscriptionsContainer !== undefined) {
        for (let i = 0; i < this.subscriptionsLabels.length; i++) {
          this.subscriptionsLabels[i]!.remove()
        }

        if (this.subscriptionsSubtitle !== undefined) {
          this.subscriptionsSubtitle.toggleAttribute('hidden', false)
        }

        this.subscriptionsContainer.textContent = ''
      }
    }
  }

  updateSocialCount(count: string) {
    if (this.socialCount) {
      this.socialCount.textContent = count
      this.socialCount.setAttribute('aria-label', `${this.pluralizeUsers(count)} watching this repository`)
    }
  }

  pluralizeUsers(userCount: string) {
    return parseInt(userCount) === 1 ? '1 user is' : `${userCount} users are`
  }

  handleDialogLabelToggle(e: CustomEvent<NotificationsDialogLabelToggledEvent>) {
    // change aria-checked attribute for the selected label
    // to make item appear selected/unselected depending on the current state
    const wasChecked = e.detail.wasChecked
    const labelId = e.detail.toggledLabelId
    const templateLabelElementClone = e.detail.templateLabelElementClone

    // add/remove selected label from the list of selected labels
    if (wasChecked) {
      // if label was checked previously and is now unchecked, remove label from subscribed labels list
      for (let i = 0; i < this.subscriptionsLabels.length; i++) {
        if (this.subscriptionsLabels[i]!.getAttribute('data-label-id') === labelId) {
          this.subscriptionsLabels[i]!.remove()
          break
        }
      }
    } else {
      templateLabelElementClone.removeAttribute('hidden')
      templateLabelElementClone.setAttribute('data-targets', 'notifications-list-subscription-form.subscriptionsLabels')

      this.subscriptionsContainer.appendChild(templateLabelElementClone)
    }
  }

  openCustomDialog(e: Event) {
    e.preventDefault()
    e.stopPropagation()
    this.menu.toggleAttribute('hidden', true)
    this.enableApplyButtonAndCheckbox()
    this.saveCurrentLabelsState()
    this.customDialog.toggleAttribute('hidden', false)
    setTimeout(() => {
      this.customDialog.querySelector<HTMLInputElement>('input[type=checkbox][autofocus]')?.focus()
    }, 0)
  }

  enableApplyButtonAndCheckbox() {
    const visibleLabels = this.customDialog.querySelectorAll<HTMLElement>('[data-type="label"]:not([hidden])')

    if (visibleLabels.length > 0) {
      this.customSubmit.removeAttribute('disabled')
      this.threadTypeCheckboxes[0]!.checked = true
    }
  }

  closeCustomDialog(e: Event) {
    e.preventDefault()
    e.stopPropagation()
    this.menu.toggleAttribute('hidden', false)
    this.customDialog.toggleAttribute('hidden', true)
    setTimeout(() => {
      this.customButton.focus()
    }, 0)
  }

  // Apply the previous state of labels selected
  resetFilterLabelsDialog(e: Event) {
    e.preventDefault()
    e.stopPropagation()

    // remove checkboxes from the dialog
    for (let idx = 0; idx < this.subscriptionsLabels.length; idx++) {
      const labelId = this.subscriptionsLabels[idx]!.getAttribute('data-label-id')

      // this is up to O(n^2) but is an im memorty alternative for dom queries, which should be faster
      for (let i = 0; i < this.dialogLabelItems.length; i++) {
        if (this.dialogLabelItems[i]!.labelId === labelId) {
          this.dialogLabelItems[i]!.setCheckedForDropdownLabel(false)
          break
        }
      }
    }

    // add checkboxes to dialog based on last applied labels
    for (let idx = 0; idx < Object.keys(this.lastAppliedLabels).length; idx++) {
      const labelId = Object.keys(this.lastAppliedLabels)[idx]

      // this is up to O(n^2) but is an im memorty alternative for dom queries, which should be faster
      for (let i = 0; i < this.dialogLabelItems.length; i++) {
        if (this.dialogLabelItems[i]!.labelId === labelId) {
          this.dialogLabelItems[i]!.setCheckedForDropdownLabel(true)
          break
        }
      }
    }

    this.subscriptionsContainer.replaceChildren(...Object.values(this.lastAppliedLabels))
    this.closeFilterLabelsDialog(e)
  }

  openFilterLabelsDialog(e: Event) {
    e.preventDefault()
    e.stopPropagation()

    this.saveCurrentLabelsState()
    this.customDialog.toggleAttribute('hidden', true)
    this.filterLabelsDialog.toggleAttribute('hidden', false)
    setTimeout(() => {
      this.filterLabelsDialog.querySelector<HTMLInputElement>('input[type=checkbox][autofocus]')?.focus()
    }, 0)
  }

  closeFilterLabelsDialog(e: Event) {
    e.preventDefault()
    e.stopPropagation()

    this.menu.toggleAttribute('hidden', true)
    this.customDialog.toggleAttribute('hidden', false)
    this.filterLabelsDialog.toggleAttribute('hidden', true)
  }

  // Apply changes from labels filter
  applyFilterLabelsDialog(e: Event) {
    e.preventDefault()
    e.stopPropagation()

    this.saveCurrentLabelsState()

    this.hideFilterSubtitle()
    this.enableIssuesCheckbox()
    this.closeFilterLabelsDialog(e)
  }

  enableIssuesCheckbox() {
    const enableCheckbox = Object.keys(this.lastAppliedLabels).length > 0

    if (enableCheckbox && this.threadTypeCheckboxes.length > 0) {
      this.threadTypeCheckboxes[0]!.checked = enableCheckbox
    }

    this.threadTypeCheckboxesUpdated()
  }

  hideFilterSubtitle() {
    const hideSubtitle = Object.keys(this.lastAppliedLabels).length > 0
    this.subscriptionsSubtitle.toggleAttribute('hidden', hideSubtitle)
  }

  // Save the selected labels and save label ids in inputs
  saveCurrentLabelsState() {
    this.lastAppliedLabels = {}
    this.labelInputs.textContent = ''

    for (let i = 0; i < this.subscriptionsLabels.length; i++) {
      const labelId = this.subscriptionsLabels[i]!.getAttribute('data-label-id')
      if (labelId) {
        this.lastAppliedLabels[labelId] = this.subscriptionsLabels[i]!.cloneNode(true)
        this.appendLabelToFormInput(labelId)
      }
    }
  }

  appendLabelToFormInput(value: string) {
    // create input in memory to append it to the form element
    const input = document.createElement('input')
    input.setAttribute('type', 'hidden')
    input.setAttribute('name', 'labels[]')
    input.setAttribute('value', value)

    this.labelInputs.appendChild(input)
  }

  detailsToggled() {
    this.menu.toggleAttribute('hidden', false)
    this.customDialog.toggleAttribute('hidden', true)
  }

  submitCustom(e: Event) {
    e.preventDefault()
    this.details.toggleAttribute('open', false)
  }

  threadTypeCheckboxesUpdated() {
    const noneSelected = !this.threadTypeCheckboxes.some(input => input.checked)

    this.customSubmit.disabled = noneSelected
  }

  closeMenu() {
    this.details.toggleAttribute('open', false)
  }
}

import {attr, controller, target} from '@github/catalyst'

export interface NotificationsDialogLabelToggledEvent {
  wasChecked: boolean
  toggledLabelId: string
  templateLabelElementClone: HTMLElement
}

@controller('notifications-dialog-label-item')
export class NotificationsDialogLabelItemElement extends HTMLElement {
  @target declare label: HTMLElement
  @target declare hiddenLabelTemplate: HTMLElement
  @target declare hiddenCheckboxInput: HTMLInputElement

  static attrPrefix = ''
  @attr declare labelId: string

  toggleDropdownLabel(e: Event) {
    e.preventDefault()
    e.stopPropagation()

    if (this.label) {
      // change aria-checked attribute for the selected label
      const wasChecked = this.label.getAttribute('aria-checked') === 'true'

      this.setCheckedForDropdownLabel(!wasChecked)

      this.dispatchEvent(
        new CustomEvent<NotificationsDialogLabelToggledEvent>('notifications-dialog-label-toggled', {
          detail: {
            wasChecked,
            toggledLabelId: this.labelId,
            templateLabelElementClone: this.hiddenLabelTemplate.cloneNode(true) as HTMLElement,
          },
          bubbles: true,
        }),
      )
    }
  }

  setCheckedForDropdownLabel(checked: boolean) {
    this.label.setAttribute('aria-checked', checked.toString())
  }
}

import {controller, target} from '@github/catalyst'
@controller('notifications-team-subscription-form')
class NotificationsTeamSubscriptionFormElement extends HTMLElement {
  @target declare details: HTMLDetailsElement

  closeMenu() {
    this.details.toggleAttribute('open', false)
  }
}

// If the current page is openable in github.dev, do so on click.
// This would be achievable without any custom JS by just using
// data-hotkey except for two things:
//  - PJAX and other replaceState-triggered location updates like
//    the `y` hotkey need to be respected.
//  - the editor cares about the hash of the page.
// So we'll construct the href client-side.
import {on} from 'delegated-events'

function isVisible(el: HTMLElement) {
  try {
    const rect = el.getBoundingClientRect()
    if (rect.height === 0 && rect.width === 0) {
      return false
    }
    if (el.style.opacity === '0' || el.style.visibility === 'hidden') {
      return false
    }
  } catch {
    // fall through to return true below
  }
  return true
}

on('click', '.js-github-dev-shortcut', function (event) {
  event.preventDefault()
  // If content exists in any visble comment field, prompt before navigating to github.dev
  for (const el of document.querySelectorAll<HTMLTextAreaElement>('textarea.js-comment-field')) {
    // eslint-disable-next-line i18n-text/no-en
    if (el.value && isVisible(el) && !confirm('Are you sure you want to open github.dev?')) {
      return
    }
  }
  // Assumption: the href of the shortcut is the base URL for
  // the serverless editor, e.g. https://github.dev/
  let target = event.currentTarget as HTMLAnchorElement
  // Some Primer elements require the target class for this callback being on a wrapper element, just naively step one level down looking for the anchor
  if (target.tagName !== 'A') {
    target = target.querySelector('a') as HTMLAnchorElement
  }
  target.pathname = window.location.pathname
  target.hash = window.location.hash
  window.location.href = target.href
})

on('click', '.js-github-dev-new-tab-shortcut', function (event) {
  // Assumption: the href of the shortcut is the base URL for
  // the serverless editor, e.g. https://github.dev/
  const target = event.currentTarget as HTMLAnchorElement
  target.pathname = window.location.pathname
  target.hash = window.location.hash
})

import {on} from 'delegated-events'
import {preservePosition} from 'scroll-anchoring'

// TODO: Refactor to use data-hotkey
/* eslint eslint-comments/no-use: off */
/* eslint-disable @github-ui/ui-commands/no-manual-shortcut-logic */
// We can't rely on `event.altKey` of the click event since in Firefox it
// doesn't accurately reflect whether Alt was pressed when Space or Enter were
// used to toggle the details element instead of a mouse.
let altPressed = false
document.addEventListener('keydown', function (event: KeyboardEvent) {
  if ('Alt' === event.key) altPressed = true
})
document.addEventListener('keyup', function (event: KeyboardEvent) {
  if ('Alt' === event.key) altPressed = false
})

on('click', '.js-toggle-outdated-comments', function (event) {
  if (!((event instanceof MouseEvent && event.altKey) || altPressed) || !(event.currentTarget instanceof HTMLElement)) {
    return
  }

  const current = event.currentTarget
  const container = current.closest<HTMLElement>('details')!

  function toggleAll() {
    const open = container.hasAttribute('open')
    for (const other of document.querySelectorAll('.js-toggle-outdated-comments')) {
      if (other !== current) {
        const otherContainer = other.closest<HTMLElement>('details')!
        otherContainer.toggleAttribute('open', open)
      }
    }
  }

  setTimeout(() => {
    preservePosition(current, toggleAll)
  })
})

/* eslint-enable @github-ui/ui-commands/no-manual-shortcut-logic */

import FilterInputElement from '@github/filter-input-element'
import RemoteInputElement from '@github/remote-input-element'
import {on} from 'delegated-events'
import {sendHydroEvent} from '../hydro-tracking'

on('tab-container-changed', '.js-branches-tags-tabs', async function (event) {
  const newTabPanel = event.detail.relatedTarget
  const tabContainer = event.currentTarget
  if (!newTabPanel || !tabContainer) return

  let oldValue
  let newControl

  for (const controlInput of tabContainer.querySelectorAll('[data-controls-ref-menu-id]')) {
    if (!(controlInput instanceof FilterInputElement || controlInput instanceof RemoteInputElement)) return
    const id = controlInput.getAttribute('data-controls-ref-menu-id')!
    const isNewControl = newTabPanel.id === id
    controlInput.hidden = !isNewControl
    if (isNewControl) {
      newControl = controlInput
    } else if (!oldValue) {
      oldValue = controlInput.input ? controlInput.input.value : ''
    }
  }
  const newInput = newControl && newControl.input
  if (newInput) {
    if (newControl && oldValue !== undefined) newInput.value = oldValue
    newInput.focus()
  }
})

on('click', '.js-branch-select-menu', event => {
  const target = event.currentTarget

  if (target instanceof HTMLDetailsElement && !target.open) {
    sendHydroEvent(target)
  }
})

import {filterSort} from '@github-ui/filter-sort'
import {compare, fuzzyScore} from '@github-ui/fuzzy-filter'
import type {QueryEvent, SearchProvider, QueryBuilderAction} from '@github-ui/query-builder-element/query-builder-api'
import {SearchItem, Octicon} from '@github-ui/query-builder-element/query-builder-api'
import type {QueryBuilderElement} from '@github-ui/query-builder-element'
import {getSuggestions} from '@github-ui/jump-to-element/model'
import {CaretPositionKind, extractRepoOrgScopes, extractTextQuery, isContentNode, isQualifier} from '../parsing/common'
import type {ParsedIntermediateRepresentation} from '../qbsearch-input-element'

export class OwnersProvider extends EventTarget implements SearchProvider {
  priority = 5
  name = 'Owners'
  singularItemName = 'owner'
  value = 'owner'
  type = 'search' as const
  manuallyDetermineFilterEligibility = true

  #suggestedOwners: string[] | null = null
  #input: HTMLElement

  queryBuilder: QueryBuilderElement

  constructor(queryBuilder: QueryBuilderElement, input: HTMLElement) {
    super()
    this.queryBuilder = queryBuilder
    this.queryBuilder.addEventListener('query', this)
    this.#input = input
  }

  async handleEvent(event: QueryEvent) {
    const state = event.parsedMetadata as ParsedIntermediateRepresentation | undefined
    const hasFocus = this.queryBuilder.hasFocus()
    if (!state || !hasFocus) {
      return []
    }

    if (state.caretPositionKind === CaretPositionKind.Text && state.ast) {
      // If the query is already scoped, don't suggest any more orgs
      if (extractRepoOrgScopes(state.ast).length) {
        return []
      }
      // Check that there are no existing scopes already applied
    } else if (state.caretPositionKind !== CaretPositionKind.Owner) {
      return []
    }

    let term = ''
    const scopedOrgs: string[] = []
    if (state.ast) {
      term = extractTextQuery(state.ast)
    }

    if (state.caretSelectedNode && isQualifier(state.caretSelectedNode)) {
      if (isContentNode(state.caretSelectedNode.content)) {
        term = state.caretSelectedNode.content.value as string
      } else {
        term = ''
      }
    }

    if (this.#suggestedOwners === null) {
      const owners = (await getSuggestions(this.#input))
        .filter(r => r.type === 'Repository')
        .map(r => r.name.split('/')[0]!)
      this.#suggestedOwners = [...new Set(owners)]
    }

    let matches = this.#suggestedOwners
    if (term.length > 0) {
      const fuzzyQuery = term.replace(/\s/g, '')
      const key = (r: string) => {
        const score = fuzzyScore(r, fuzzyQuery)
        return score > 0 ? {score, text: r} : null
      }
      matches = filterSort(this.#suggestedOwners, key, compare)
    }

    // Filter matches match orgs specified in the query
    if (scopedOrgs.length > 0) {
      matches = matches.filter(r => {
        const org = r.split('/')[0]!.toLowerCase()
        return scopedOrgs.find(o => org.startsWith(o))
      })
    }

    for (const suggestion of matches.slice(0, 5)) {
      let action: QueryBuilderAction = {
        url: `/${suggestion}`,
      }

      if (state.caretSelectedNode && isQualifier(state.caretSelectedNode)) {
        let rewriteStart = state.caretSelectedNode.location.end
        let rewriteEnd = state.caretSelectedNode.location.end
        if (isContentNode(state.caretSelectedNode.content)) {
          rewriteStart = state.caretSelectedNode.content.location.start
          rewriteEnd = state.caretSelectedNode.content.location.end
        }

        const newQuery = `${state.query.slice(0, rewriteStart) + suggestion} ${state.query.slice(rewriteEnd)}`
        action = {
          replaceQueryWith: newQuery,
          moveCaretTo: rewriteStart + suggestion.length + 1,
        }
      }

      this.dispatchEvent(
        new SearchItem({
          value: suggestion,
          icon: Octicon.Repo,
          priority: 0,
          action,
        }),
      )
    }
  }
}

import {validate} from './behaviors/html-validation'

interface PasswordOptions {
  minimumCharacterCount: number
  passphraseLength: number
}

interface Result {
  valid: boolean
  hasMinimumCharacterCount: boolean
  hasMinimumPassphraseLength: boolean
  hasLowerCase: boolean
  hasNumber: boolean
}

class PasswordStrengthElement extends HTMLElement {
  connectedCallback() {
    this.addEventListener('input', onInput)
  }

  disconnectedCallback() {
    this.removeEventListener('input', onInput)
  }
}

if (!window.customElements.get('password-strength')) {
  window.PasswordStrengthElement = PasswordStrengthElement
  window.customElements.define('password-strength', PasswordStrengthElement)
}

declare global {
  interface Window {
    PasswordStrengthElement: typeof PasswordStrengthElement
  }
}

function onInput(event: Event) {
  const passwordStrength = event.currentTarget
  if (!(passwordStrength instanceof PasswordStrengthElement)) return
  const passwordInput = event.target
  if (!(passwordInput instanceof HTMLInputElement)) return
  const form = passwordInput.form
  if (!(form instanceof HTMLFormElement)) return

  const result = validatePassword(passwordInput.value, {
    minimumCharacterCount: Number(passwordStrength.getAttribute('minimum-character-count')),
    passphraseLength: Number(passwordStrength.getAttribute('passphrase-length')),
  })

  if (result.valid) {
    passwordInput.setCustomValidity('')
    const errorHint = passwordStrength.querySelector('dl.form-group')
    if (errorHint) {
      errorHint.classList.remove('errored')
      errorHint.classList.add('successed')
    }
  } else if (passwordStrength.getAttribute('skip-custom-validity') !== 'true') {
    passwordInput.setCustomValidity(passwordStrength.getAttribute('invalid-message') || 'Invalid')
  }

  highlightPasswordStrengthExplainer(passwordStrength, result)
  validate(form)
}

function validatePassword(password: string, options: PasswordOptions): Result {
  const result = {
    valid: false,
    hasMinimumCharacterCount: password.length >= options.minimumCharacterCount,
    hasMinimumPassphraseLength: options.passphraseLength !== 0 && password.length >= options.passphraseLength,
    hasLowerCase: /[a-z]/.test(password),
    hasNumber: /\d/.test(password),
  }
  result.valid =
    result.hasMinimumPassphraseLength || (result.hasMinimumCharacterCount && result.hasLowerCase && result.hasNumber)
  return result
}

function highlightPasswordStrengthExplainer(element: HTMLElement, result: Result) {
  const moreThanNCharactersEl = element.querySelector('[data-more-than-n-chars]')
  const minCharsEl = element.querySelector<HTMLElement>('[data-min-chars]')!
  const numberReqEl = element.querySelector<HTMLElement>('[data-number-requirement]')!
  const letterReqEl = element.querySelector<HTMLElement>('[data-letter-requirement]')!
  const errorClasses =
    element
      .getAttribute('error-class')
      ?.split(' ')
      .filter(t => t.length > 0) || []
  const passClasses =
    element
      .getAttribute('pass-class')
      ?.split(' ')
      .filter(t => t.length > 0) || []

  for (const part of [moreThanNCharactersEl, minCharsEl, numberReqEl, letterReqEl]) {
    part?.classList.remove(...errorClasses, ...passClasses)
  }

  if (result.hasMinimumPassphraseLength && moreThanNCharactersEl) {
    moreThanNCharactersEl.classList.add(...passClasses)
  } else if (result.valid) {
    minCharsEl.classList.add(...passClasses)
    numberReqEl.classList.add(...passClasses)
    letterReqEl.classList.add(...passClasses)
  } else {
    const charTextClasses = result.hasMinimumCharacterCount ? passClasses : errorClasses
    const numberTextClasses = result.hasNumber ? passClasses : errorClasses
    const caseTextClasses = result.hasLowerCase ? passClasses : errorClasses

    moreThanNCharactersEl?.classList.add(...errorClasses)
    minCharsEl.classList.add(...charTextClasses)
    numberReqEl.classList.add(...numberTextClasses)
    letterReqEl.classList.add(...caseTextClasses)
  }
}

// performTransition
//
// CSS3 transitions have some major pitfalls. First trying to transition
// elements from `display:none` to `display:block.` And also dealing with
// computed properties like `height:auto`.
//
// This helper attempts to deal with those issues while still defining
// the transitions in pure css.
//
// Behaviors that intend to support these special case transitions
// should call `performTransition` when they add or remove their state
// classes.
//
// Any element that is performing a transition needs to be annotated
// with the `js-transitionable` class name.
//
// @example
//
// <div class="js-transitionable collapse">
//   Slide down
// </div>
//
// .collapse {
//   display: none;
//   position: relative;
//   height: 0;
//   overflow: hidden;
//   @include transition(0.35s, height, ease);
// }
// .collapse.open {
//   display: block;
//   height: auto;
// }
//
// performTransition document.querySelector('.collapse', () => {
//   this.classList.add('open')
// })

const supportsTransitions = 'ontransitionend' in window

// DEPRECATED: PerformTransition is deprecated.
export default function performTransition(container: HTMLElement, cb: () => void) {
  if (!supportsTransitions) {
    cb()
    return
  }

  const els = Array.from(container.querySelectorAll('.js-transitionable'))
  if (container.classList.contains('js-transitionable')) els.push(container)

  for (const el of els) {
    const transitionHeight = isTransitioningHeight(el)
    if (!(el instanceof HTMLElement)) continue

    el.addEventListener(
      'transitionend',
      () => {
        el.style.display = ''
        el.style.visibility = ''

        if (transitionHeight) {
          withoutTransition(el, function () {
            el.style.height = ''
          })
        }
      },
      {once: true},
    )

    el.style.boxSizing = 'content-box'
    el.style.display = 'block'
    el.style.visibility = 'visible'

    if (transitionHeight) {
      withoutTransition(el, function () {
        el.style.height = getComputedStyle(el).height
      })
    }

    // force reflow
    // eslint-disable-next-line @typescript-eslint/no-unused-expressions
    el.offsetHeight
  }

  cb()

  for (const el of els) {
    if (!(el instanceof HTMLElement)) continue
    if (isTransitioningHeight(el)) {
      const currentHeight = getComputedStyle(el).height
      el.style.boxSizing = ''
      if (currentHeight === '0px') {
        el.style.height = `${el.scrollHeight}px`
      } else {
        el.style.height = '0px'
      }
    }
  }
}

// Detect if element is transitioning its height property.
function isTransitioningHeight(el: Element) {
  return getComputedStyle(el).transitionProperty === 'height'
}

// Apply style change callback w/o triggering a transition.
function withoutTransition(el: HTMLElement, cb: () => void) {
  el.style.transition = 'none'
  cb()
  // eslint-disable-next-line @typescript-eslint/no-unused-expressions
  el.offsetHeight
  el.style.transition = ''
}

// Append any window.location.hash changes to the permalink.
//
// For example, if you're viewing:
// /github/linguist/blob/master/lib/linguist/languages.yml#L12
//
// You probably want the permalink to preserve the #L12, and go to:
// /github/linguist/blob/SHA/lib/linguist/languages.yml#L12
//
//
// Also update link that we want to keep in sync with the permalink change.
//
// For example, if you `y` a Markdown file and click the "Display as source blob"
// button, probably you want its link (href) to change from:
// /github/linguist/blob/master/README.md?plain=1
//
// to:
// /github/linguist/blob/SHA/README.md?plain=1
import {on} from 'delegated-events'
import {updateUrl} from '@github-ui/history'

on('click', '.js-permalink-shortcut', function (event) {
  const target = event.currentTarget as HTMLAnchorElement
  try {
    updateUrl(target.href + window.location.hash)
  } catch {
    window.location.href = target.href + window.location.hash
  }
  for (const element of document.querySelectorAll('.js-permalink-replaceable-link')) {
    if (element instanceof HTMLAnchorElement) {
      element.href = element.getAttribute('data-permalink-href')!
    }
  }
  event.preventDefault()
})

import {remoteForm} from '@github-ui/remote-form'

remoteForm('.js-permission-menu-form', async function (form, wants) {
  const success = form.querySelector<HTMLElement>('.js-permission-success')!
  const error = form.querySelector<HTMLElement>('.js-permission-error')!

  success.hidden = true
  error.hidden = true
  form.classList.add('is-loading')

  let response
  try {
    response = await wants.json()
  } catch {
    // If the request errored, we'll set the error state and return.
    form.classList.remove('is-loading')
    error.hidden = false
    return
  }

  if (response.status === 200) {
    const selectPanel = form.querySelector('select-panel, select-panel-experimental')
    if (selectPanel) {
      const buttonLabelSpan = form.querySelector('span.Button-label')
      if (buttonLabelSpan) {
        buttonLabelSpan.textContent = `Role: ${response.json.action}`
      }
    }
  }

  form.classList.remove('is-loading')
  success.hidden = false

  const container = form.closest('.js-org-repo')
  if (container) {
    const data = response.json
    container.classList.toggle('with-higher-access', data['members_with_higher_access'])
  }
})

import {observe} from '@github/selector-observer'

export function getPlatform(): string | null {
  if (/Windows/.test(navigator.userAgent)) {
    return 'windows'
  }
  if (/Macintosh/.test(navigator.userAgent)) {
    return 'mac'
  }
  return null
}

function runningOnPlatform(element: Element): boolean {
  const platforms = (element.getAttribute('data-platforms') || '').split(',')
  const platform = getPlatform()
  return Boolean(platform && platforms.includes(platform))
}

observe('.js-remove-unless-platform', function (el) {
  if (!runningOnPlatform(el)) {
    el.remove()
  }
})

