/* eslint eslint-comments/no-use: off */

import '@github-ui/include-fragment'
import {IncludeFragmentElement} from '@github/include-fragment-element'
import {controller, target, attr} from '@github/catalyst'

const DEFAULT_INTERVAL = 1000
const DEFAULT_MULTIPLIER = 1.5

@controller('poll-include-fragment')
class PollIncludeFragmentElement extends IncludeFragmentElement {
  @target declare retryButton: HTMLButtonElement | null
  @attr intervalMilliseconds = DEFAULT_INTERVAL
  @attr backoffMultiplier = DEFAULT_MULTIPLIER

  pollingTimeout: NodeJS.Timeout | null = null

  override async fetch(request: Request, ms?: number): Promise<Response> {
    const response = await super.fetch(request)
    // Protecting from NaN here as per the documentation describes that it will be
    // return 0 if attribute doesn't exist: https://github.github.io/catalyst/guide/attrs/

    let interval = ms || this.intervalMilliseconds
    if (!interval || isNaN(interval)) {
      interval = DEFAULT_INTERVAL
    }
    const multiplier = isNaN(this.backoffMultiplier) ? DEFAULT_MULTIPLIER : this.backoffMultiplier

    if (response.status === 202) {
      await new Promise(resolve => {
        this.pollingTimeout = setTimeout(resolve, interval)
      })
      return this.fetch(request, interval * multiplier)
    } else {
      return response
    }
  }

  override refetch() {
    this.cancelPolling()
    return super.refetch()
  }

  override connectedCallback() {
    super.connectedCallback()

    if (this.retryButton) {
      this.retryButton.addEventListener('click', () => {
        this.refetch()
      })
    }
  }

  disconnectedCallback() {
    this.cancelPolling()
  }

  private cancelPolling() {
    if (this.pollingTimeout) {
      clearTimeout(this.pollingTimeout)
    }
  }
}

import type {IncludeFragmentElement} from '@github/include-fragment-element'
import {ensureExpanded} from '../behaviors/details'
import {findElementByFragmentName} from '../fragment-target'
import {loadDeferredContent} from '../behaviors/include-fragment'
import {observe} from '@github/selector-observer'
import {on} from 'delegated-events'
import {scrollIntoView} from '../sticky-scroll-into-view'
import {announce} from '@github-ui/aria-live'

observe('.js-diff-progressive-container', function (container) {
  processProgressiveContainer(container)

  const loader = container.querySelector('.js-diff-progressive-loader')
  if (!loader) {
    return
  }

  loader.addEventListener('load', function () {
    processProgressiveContainer(container)
  })
})

function loadResolvedComments(container: Element, anchor: string): void {
  const commentContainers = container.querySelectorAll('.js-comment-container')

  for (const commentContainer of commentContainers) {
    const threadCommentIds = commentContainer.getAttribute('data-hidden-comment-ids')

    if (threadCommentIds) {
      const commentIds = threadCommentIds.split(',')
      const anchorCommentId = anchor.match(/\d+/g)?.[0]

      if (anchorCommentId && commentIds.includes(anchorCommentId)) {
        loadDeferredContent(commentContainer)
        break
      }
    }
  }
}

function processProgressiveContainer(container: Element): void {
  const anchor = urlAnchor()
  if (!anchor) {
    return
  }

  scrollToAnchor(container, anchor)

  const entryContainer = getEntryFromAnchor(container, anchor)
  if (!entryContainer) {
    return
  }

  scrollIntoView(entryContainer)
  loadDiff(entryContainer)
}

observe('.js-diff-load-container', function (container) {
  const loader = container.querySelector('.js-diff-entry-loader')
  if (!loader) {
    return
  }

  loader.addEventListener('load', function () {
    const fileContainer = container.closest<HTMLElement>('.js-file')!
    fileContainer.classList.remove('hide-file-notes-toggle')

    const loadDiffPathName = fileContainer.getAttribute('data-tagsearch-path')
    announce(`loaded diff for ${loadDiffPathName}`)

    const anchor = urlAnchor()
    if (!anchor) {
      return
    }

    scrollToAnchor(container, anchor)
  })
})

on('click', '.js-diff-load', function (event) {
  if ((event.target as HTMLElement).classList.contains('js-ignore-this')) {
    return
  }

  const entryContainer = event.currentTarget.closest<HTMLElement>('.js-diff-load-container')!
  loadDiff(entryContainer)
  entryContainer?.focus()
  announce('Loading...')
})

function urlAnchor(): string {
  return window.location.hash.slice(1)
}

function scrollToAnchor(container: Element, anchor: string): void {
  let target: Element | null

  // If anchor is a range, cut off the range characters
  // E.g. 'diff-2b939de295abbeb764a2b0de8fe0e690L5-R7'
  // to   'diff-2b939de295abbeb764a2b0de8fe0e690L5'
  if (anchor.match(/^diff-.+[LR]\d+-[LR]\d+/)) {
    target = findElementByFragmentName(container.ownerDocument, anchor.substring(0, anchor.indexOf('-', 5)))
  } else {
    target = findElementByFragmentName(container.ownerDocument, anchor)
  }

  if (target && container.contains(target)) {
    ensureExpanded(target)
    scrollIntoView(target)
  } else {
    loadResolvedComments(container, anchor)
  }
}

function getEntryFromAnchor(container: Element, anchor: string): Element | undefined {
  const entryContainer = getEntryFromDiffAnchor(container, anchor)
  if (entryContainer) {
    return entryContainer
  }

  return getEntryFromCommentAnchor(container, anchor)
}

function getEntryFromDiffAnchor(container: Element, anchor: string): Element | undefined {
  const match = /^(diff-[0-9a-f]{32})(?:[L|R]\d+)?$/.exec(anchor)
  if (!match) {
    return
  }

  const entryId = match[1]
  const entryAnchor = container.querySelector(`a[name='${entryId}']`)
  if (!entryAnchor) {
    return
  }

  const entryContainer = entryAnchor.nextElementSibling
  if (entryContainer && !entryContainer.querySelector('.js-diff-load-container')) {
    return
  }

  return entryContainer!
}

function getEntryFromCommentAnchor(container: Element, anchor: string): Element | undefined {
  const match = /^(?:r|commitcomment-)(\d+)$/.exec(anchor)
  if (!match) {
    return
  }

  const commentId = match[1]
  const commentDummy = container.querySelector(`#diff-with-comment-${commentId}`)

  if (!commentDummy) {
    return
  }
  const entryContainer = commentDummy.closest('.js-file')

  return entryContainer!
}

function loadDiff(entryContainer: Element): Promise<string> {
  const fragment = entryContainer.querySelector<IncludeFragmentElement>('.js-diff-entry-loader')!
  const placeholder = entryContainer.querySelector('.js-diff-placeholder')!
  const button = entryContainer.querySelector<HTMLButtonElement>('button.js-diff-load')!
  const buttonText = entryContainer.querySelector<HTMLElement>('.js-button-text')!

  // show loader and disable button
  placeholder.setAttribute('fill', "url('#animated-diff-gradient')")
  buttonText.textContent = button.getAttribute('data-disable-with') || ''
  button.disabled = true

  const url = new URL(fragment.getAttribute('data-fragment-url') || '', window.location.origin)
  fragment.src = url.toString()

  return fragment.data
}

import type {Item, Octicon, ProviderResponse} from '@github-ui/command-palette-element'
import {Query} from '../query'
import {RemoteProvider} from './remote-provider'

/**
 * This provides results to the command palette.
 *
 * It prefetches results from the server and filters them on the client-side as
 * the user types. Results are prefetched when the command palette is activated
 * or when the scope changes.
 *
 * Because the results are already loaded, this provider has near-zero latency.
 *
 * If your data source has a bounded size that is 1,000 or less, a prefetched
 * provider will offer a better user experience with less server load.
 */
export class PrefetchedProvider extends RemoteProvider {
  declare octicons: Octicon[]
  maxItems = 1000
  scopedItems: {
    [scopeId: string]: Item[]
  } = {}
  cachedOcticons: {
    [scopeId: string]: Octicon[]
  } = {}

  override clearCache() {
    super.clearCache()
    this.scopedItems = {}
    this.cachedOcticons = {}
  }

  override get debounce() {
    return 0
  }

  async prefetch(query: Query) {
    if (!this.scopeMatch(query)) return
    // No need to fetch from server if we already have the results.
    if (this.scopedItems[query.scope.id]) return

    // When pre-fetching we want results from a query with no query text.
    // A query with no text should generally return a complete set of results
    // that the fuzzy filter can then filter based on the query text.
    const blankQuery = new Query('', query.mode, {
      subjectId: query.subjectId,
      subjectType: query.subjectType,
      returnTo: query.returnTo,
      scope: query.scope,
    })
    const responseData = await this.fetchSrc(blankQuery, query.mode)
    this.octicons = responseData.octicons || []
    const items = responseData.results || []

    // Cache these results for this scope. fetch can then return them immediately.
    this.scopedItems[query.scope.id] = items
    this.cachedOcticons[query.scope.id] = this.octicons
  }

  override async fetch(query: Query, _isEmpty: boolean): Promise<ProviderResponse> {
    const items = this.scopedItems[query.scope.id] || []
    const octicons = this.cachedOcticons[query.scope.id] || []

    const matchingItems = this.fuzzyFilter(items, query)
    return {results: matchingItems.slice(0, this.maxItems), octicons}
  }
}

import {observe} from '@github/selector-observer'

observe('body.js-print-popup', () => {
  window.print()
  setTimeout(window.close, 1000)
})

import {isDetailsTargetExpanded, toggleDetailsTarget} from '../details'
import {fetchSafeDocumentFragment} from '@github-ui/fetch-utils'
import hashChange from '../hash-change'
import {loadDeferredContent} from '../include-fragment'
import {scrollIntoView} from '../../sticky-scroll-into-view'
import {observe} from '@github/selector-observer'

const SCROLL_WAIT_MEDIA_TIMEOUT = 5000
const COMMENT_IMAGE = '.js-comment-body img'
const COMMENT_VIDEO = '.js-comment-body video'

hashChange(function () {
  focusOrLoadElement()
})

observe('.js-timeline-progressive-focus-container', scrollToFocusTimelineEvent)

window.addEventListener('sticky-header-rendered', () => {
  scrollToFocusTimelineEvent()
})

function scrollToFocusTimelineEvent() {
  const anchor = urlAnchor()
  if (!anchor) return

  const pullTimeline = document.querySelector<HTMLElement>('.js-pull-discussion-timeline')
  if (pullTimeline) return

  const target = document.getElementById(anchor)

  if (target) {
    focusElement(target)
  }
}

function focusOrLoadElement(shouldLoadElement = true): void {
  const anchor = urlAnchor()
  if (!anchor) return

  const target = document.getElementById(anchor)
  if (target) {
    focusElement(target)
  } else {
    if (loadComments(anchor)) return

    const loader = document.querySelector<HTMLElement>('#js-timeline-progressive-loader')

    if (loader && shouldLoadElement) {
      loadElement(anchor, loader)
    }
  }
}

function loadComments(anchor: string): boolean {
  return (
    loadResolvedComments(anchor) ||
    loadHiddenComments(anchor, '.js-thread-hidden-comment-ids') ||
    loadHiddenComments(anchor, '.js-review-hidden-comment-ids')
  )
}

function loadResolvedComments(anchor: string): boolean {
  const commentContainer = findCommentContainer(anchor, '.js-comment-container')
  if (!commentContainer) return false

  loadDeferredContent(commentContainer)
  return true
}

function loadHiddenComments(anchor: string, selector: string): boolean {
  const commentContainer = findCommentContainer(anchor, selector)
  if (!commentContainer) return false

  commentContainer.addEventListener('page:loaded', function () {
    focusOrLoadElement()
  })
  commentContainer.querySelector<HTMLButtonElement>('button[type=submit]')!.click()
  return true
}

function findCommentContainer(anchor: string, selector: string): Element | null {
  const commentContainers = document.querySelectorAll(selector)

  for (const commentContainer of commentContainers) {
    const threadCommentIds = commentContainer.getAttribute('data-hidden-comment-ids')

    if (threadCommentIds) {
      const commentIds = threadCommentIds.split(',')
      const anchorCommentId = anchor.match(/\d+/g)?.[0]

      if (anchorCommentId && commentIds.includes(anchorCommentId)) {
        return commentContainer
      }
    }
  }
  return null
}

observe('.js-inline-comments-container', function (container) {
  const anchor = urlAnchor()
  if (!anchor) return

  const target = document.getElementById(anchor)

  if (target && container.contains(target)) {
    focusElement(target)
  }
})

// adds support for deep-link loading discussion comments when the comment thread is nested
observe('#js-discussions-timeline-anchor-loader', {
  constructor: HTMLElement,
  add: element => {
    const existingProgressiveLoader = document.querySelector('#js-timeline-progressive-loader')
    if (existingProgressiveLoader) return

    const anchor = urlAnchor()
    if (!anchor) return

    const target = document.getElementById(anchor)
    if (!target) {
      loadElement(anchor, element)
    }
  },
})

// resolves when comment body videos have loaded enough data to render the preview image
async function videosReady(): Promise<unknown> {
  const videos: NodeListOf<HTMLVideoElement> = document.querySelectorAll(COMMENT_VIDEO)
  const videoLoads = Array.from(videos).map(v => {
    return new Promise<HTMLVideoElement>(resolve => {
      if (v.readyState >= v.HAVE_METADATA) {
        resolve(v)
      } else {
        // don't wait forever :)
        const timeout = setTimeout(() => resolve(v), SCROLL_WAIT_MEDIA_TIMEOUT)
        const done = () => {
          clearTimeout(timeout)
          resolve(v)
        }
        v.addEventListener('loadeddata', () => {
          if (v.readyState >= v.HAVE_METADATA) done()
        })
        v.addEventListener('error', () => done())
      }
    })
  })
  return Promise.all(videoLoads)
}

// resolves when comment body images are loaded
async function imagesReady(): Promise<unknown> {
  const images: NodeListOf<HTMLImageElement> = document.querySelectorAll(COMMENT_IMAGE)
  const imageLoads = Array.from(images).map(i => {
    new Promise<HTMLImageElement>(resolve => {
      if (i.complete) {
        resolve(i)
      } else {
        const timeout = setTimeout(() => resolve(i), SCROLL_WAIT_MEDIA_TIMEOUT)
        const done = () => {
          clearTimeout(timeout)
          resolve(i)
        }
        i.addEventListener('load', () => done())
        i.addEventListener('error', () => done())
      }
    })
  })
  return Promise.all(imageLoads)
}

async function mediaLoaded(): Promise<unknown> {
  return Promise.all([videosReady(), imagesReady()])
}

async function focusElement(element: HTMLElement): Promise<void> {
  await mediaLoaded()
  expandDetailsIfPresent(element)
  const link = element.querySelector<HTMLElement>(`[href='#${element.id}']`)

  scrollIntoView(element)
  if (link) {
    const oldValue = link.getAttribute('data-turbo')
    link.setAttribute('data-turbo', 'false')
    setTimeout(() => {
      link.click()
    }, 0)
    if (oldValue === null) {
      link.removeAttribute('data-turbo')
    } else {
      link.setAttribute('data-turbo', oldValue)
    }
  }
}

async function loadElement(anchor: string, loader: HTMLElement): Promise<void> {
  if (!loader) return

  const path = loader.getAttribute('data-timeline-item-src')
  if (!path) return

  const url = new URL(path, window.location.origin)
  const params = new URLSearchParams(url.search.slice(1))
  params.append('anchor', anchor)
  url.search = params.toString()

  let html
  try {
    html = await fetchSafeDocumentFragment(document, url.toString())
  } catch {
    return
  }

  const newTimelineItem = html.querySelector('.js-timeline-item')
  if (!newTimelineItem) return

  const gid = newTimelineItem.getAttribute('data-gid')
  if (!gid) return

  const currentTimelineItem = document.querySelector(`.js-timeline-item[data-gid='${gid}']`)

  if (currentTimelineItem) {
    currentTimelineItem.replaceWith(newTimelineItem)

    focusOrLoadElement(false)
  } else {
    const container = document.getElementById('js-progressive-timeline-item-container')
    if (container) container.replaceWith(html)
    focusOrLoadElement(false)
  }
}

function expandDetailsIfPresent(element: HTMLElement): void {
  const detailsContainer = element.closest<HTMLElement>('details, .js-details-container')
  if (!detailsContainer) return
  if (detailsContainer.nodeName === 'DETAILS') {
    detailsContainer.setAttribute('open', 'open')
  } else if (!isDetailsTargetExpanded(detailsContainer)) {
    toggleDetailsTarget(detailsContainer)
  }
}

function urlAnchor(): string {
  return window.location.hash.slice(1)
}

import {filterSort} from '@github-ui/filter-sort'
import {compare, fuzzyScore} from '@github-ui/fuzzy-filter'
import {
  type QueryEvent,
  FilterItem,
  type FilterProvider,
  Octicon,
} from '@github-ui/query-builder-element/query-builder-api'
import type {QueryBuilderElement} from '@github-ui/query-builder-element'
import {getSuggestions} from '@github-ui/jump-to-element/model'
import {CaretPositionKind, isContentNode, isQualifier} from '../parsing/common'
import type {ParsedIntermediateRepresentation} from '../qbsearch-input-element'

interface Project {
  name: string
  path: string
}

export class ProjectsProvider extends EventTarget implements FilterProvider {
  priority = 8
  name = 'Projects'
  singularItemName = 'project'
  value = 'project'
  type = 'filter' as const
  manuallyDetermineFilterEligibility = true

  #suggestedProjects: Project[] | null = null
  #input: HTMLElement

  queryBuilder: QueryBuilderElement

  constructor(queryBuilder: QueryBuilderElement, input: HTMLElement) {
    super()
    this.queryBuilder = queryBuilder
    this.queryBuilder.addEventListener('query', this)
    this.#input = input
  }

  async handleEvent(event: QueryEvent) {
    const state = event.parsedMetadata as ParsedIntermediateRepresentation | undefined
    const hasFocus = this.queryBuilder.hasFocus()
    if (!state || !hasFocus || state.caretPositionKind !== CaretPositionKind.Text) {
      return []
    }

    let term = state.query
    if (state.caretSelectedNode && isQualifier(state.caretSelectedNode)) {
      if (isContentNode(state.caretSelectedNode.content)) {
        term = state.caretSelectedNode.content.value as string
      } else {
        term = ''
      }
    }

    if (this.#suggestedProjects === null) {
      this.#suggestedProjects = (await getSuggestions(this.#input))
        .filter(r => r.type === 'Project')
        .map(r => {
          return {
            name: r.name,
            path: r.path,
          }
        })
    }

    let matches = this.#suggestedProjects.slice(0, 4)
    if (term.length > 0) {
      const fuzzyQuery = term.replace(/\s/g, '')
      const key = (p: Project) => {
        const score = fuzzyScore(p.name, fuzzyQuery)
        return score > 0 ? {score, text: p.name} : null
      }
      matches = filterSort(this.#suggestedProjects, key, compare)
    }

    for (const suggestion of matches.slice(0, 5)) {
      this.dispatchEvent(
        new FilterItem({
          filter: 'project',
          value: suggestion.name,
          icon: Octicon.Project,
          priority: 0,
          action: {
            url: suggestion.path,
          },
        }),
      )
    }
  }
}

import {on} from 'delegated-events'
import {remoteForm} from '@github-ui/remote-form'
import {updateUrl} from '@github-ui/history'

on('click', '.js-rendered, .js-source', function (event) {
  const button = event.currentTarget
  if (button.classList.contains('selected')) {
    event.preventDefault()
    return
  }

  updateWindowLocation(button)
  updateSelectedButton(button)
})

remoteForm('.js-prose-diff-toggle-form', async function (form, wants) {
  const entryContainer = form.closest<HTMLElement>('.js-details-container')!
  const fileContent = entryContainer.querySelector<HTMLElement>('.js-file-content')!
  const fileHeader = entryContainer.querySelector<HTMLElement>('.js-file-header')

  const data = await wants.html()
  while (fileContent.lastChild) {
    fileContent.removeChild(fileContent.lastChild)
  }
  fileContent.append(data.html)

  entryContainer.classList.toggle('display-rich-diff')

  const targetButton = fileHeader?.querySelector<HTMLButtonElement>(
    'button.js-source[aria-current="true"], button.js-rendered[aria-current="true"]',
  )

  requestAnimationFrame(() => {
    targetButton?.focus()
  })
})

function updateWindowLocation(button: Element) {
  const fileHeader = button.closest<HTMLElement>('.js-file-header')!
  const switchToRendered = button.classList.contains('js-rendered')
  const switchToSource = button.classList.contains('js-source')
  const shortPath = fileHeader.getAttribute('data-short-path')!
  const anchor = fileHeader.getAttribute('data-anchor')!

  const url = new URL(window.location.href, window.location.origin)
  const searchParams = new URLSearchParams(url.search.slice(1))
  url.hash = anchor
  if (switchToRendered) {
    searchParams.set('short_path', shortPath)
  } else if (switchToSource) {
    searchParams.delete('short_path')
  }
  url.search = searchParams.toString()

  updateUrl(url.toString())
}

function updateSelectedButton(button: Element) {
  for (const element of document.querySelectorAll('.js-rendered, .js-source')) {
    element.classList.remove('selected')
    element.removeAttribute('aria-current')
  }

  button.classList.add('selected')
  button.setAttribute('aria-current', 'true')
}

import {on} from 'delegated-events'

on('click', '.js-rich-diff.collapsed .js-expandable', function (event) {
  if (!(event.target instanceof Element)) return
  event.preventDefault()
  const container = event.target.closest('.js-rich-diff')!
  container.classList.remove('collapsed')
})

on('click', '.js-show-rich-diff', function (event) {
  const warn = event.currentTarget.closest('.js-warn-no-visible-changes')
  if (!warn) return

  /* eslint-disable-next-line github/no-d-none */
  warn.classList.add('d-none')

  const container = warn.parentElement!

  const message = container.querySelector('.js-no-rich-changes')
  if (message) {
    /* eslint-disable-next-line github/no-d-none */
    message.classList.remove('d-none')
  }
})

import {type Item, type ProviderResponse, ProviderBase as ProviderBaseAPI} from '@github-ui/command-palette-element'
import type {Query} from './query'

/**
 * This abstract class defines the shared proprieties of all providers (defined within the command palette).
 */
export abstract class ProviderBase extends ProviderBaseAPI {
  abstract override fetch(query: Query, isEmpty: boolean): Promise<ProviderResponse>
  abstract override enabledFor(query: Query): boolean
  abstract override clearCache(): void
  abstract override get hasCommands(): boolean
  abstract override get debounce(): number

  /**
   * Filter and sort by relevance.
   *
   * Filtering is done by fuzzy matching against the title using fzy.js. During
   * filtering, items are updated with a score.
   *
   * @param items that should be filtered and sorted
   * @param query used to filter items
   * @param minScore items with a score greater than this will be returned (default 0)
   * @returns items that match query sorted by relevance
   */
  override fuzzyFilter<T extends Item = Item>(items: T[], query: Query, minScore = 0) {
    if (query.isBlank()) {
      return items
    }

    const matchingItems = [] as T[]
    for (const item of items) {
      const score = item.calculateScore(query.text)
      if (score > minScore) {
        matchingItems.push(item)
      }
    }

    return matchingItems
  }
}

import type {Provider, ProviderResponse} from '@github-ui/command-palette-element'
import type {Query} from './query'

/**
 * This is the base for all ProviderElements. It defines the shared interface/attributes between
 * the provider elements, most notably it contains a `Provider` attribute.
 */
export abstract class ProviderElement extends HTMLElement {
  provider: Provider | undefined
  declare _lastFetchQuery: Query

  async fetchWithDebounce(query: Query, isEmpty: boolean): Promise<ProviderResponse> {
    if (!this.provider) return {results: []}

    // Improve debounce to use library https://github.com/github/platform-ux/issues/696
    this._lastFetchQuery = query
    await this.delay(this.provider.debounce)

    if (this._lastFetchQuery !== query) {
      return {results: []}
    } else {
      return this.provider.fetch(query, isEmpty)
    }
  }

  private delay(wait: number) {
    return new Promise(resolve => setTimeout(resolve, wait))
  }
}

/**
 * This file contains main window commands for pull requests.
 *
 * To add another command, define a new subclass and append the
 * class to the default export at the bottom of the file.
 */
import {EditIssueBody, EditIssueTitle} from './issue'
import {ClipboardCopyElement} from '@github/clipboard-copy-element'
import type CommandPalette from '../command-palette-element'
import {MainWindowCommand} from '../main-window-command'
import {OpenCodespace} from './codespaces'
import {copyText} from '@github-ui/copy'

class EditPullRequestBody extends EditIssueBody {
  override title = 'Edit pull request body'

  pullRequestBody() {
    return document.querySelector('.js-command-palette-pull-body')
  }

  isPullRequest() {
    return !!this.pullRequestBody()
  }

  override isApplicable() {
    return this.isPullRequest()
  }
}

class EditPullRequestTitle extends EditIssueTitle {
  override title = 'Edit pull request title'

  pullRequestBody() {
    return document.querySelector('.js-command-palette-pull-body')
  }

  isPullRequest() {
    return !!this.pullRequestBody()
  }

  override isApplicable() {
    return this.fetchButton() instanceof HTMLButtonElement && this.isPullRequest()
  }
}

class UpdateBranch extends MainWindowCommand {
  override title = 'Update current branch'
  override icon = 'sync-color-fg-muted'

  override isApplicable() {
    return this.fetchButton() instanceof HTMLButtonElement
  }

  fetchButton() {
    return document.querySelector<HTMLButtonElement>('.js-update-branch-form button')
  }

  override run() {
    const button = this.fetchButton()

    if (button) {
      button.scrollIntoView({behavior: 'smooth', block: 'center'})
      button.click()
    }
  }
}

class ConvertToDraft extends MainWindowCommand {
  override title = 'Convert to draft'
  override icon = 'git-pull-request-draft-color-fg-muted'

  override isApplicable() {
    return this.fetchButton() instanceof HTMLButtonElement
  }

  fetchButton() {
    return document.querySelector<HTMLButtonElement>('.js-convert-to-draft')
  }

  override run() {
    const details = this.fetchButton()?.closest<HTMLDetailsElement>('details')

    if (details) {
      details.open = true

      setTimeout(() => {
        details.querySelector<HTMLButtonElement>('.js-convert-to-draft')?.focus()
      }, 0)
    }
  }
}

class CopyBranchName extends MainWindowCommand {
  override title = 'Copy current branch name'
  override icon = 'copy-color-fg-muted'

  override isApplicable() {
    return this.fetchClipboardCopy() instanceof ClipboardCopyElement
  }

  fetchClipboardCopy() {
    return document.querySelector('.js-copy-branch')
  }

  override async run(commandPalette: CommandPalette) {
    const cloneContainer = this.fetchClipboardCopy()
    if (cloneContainer instanceof ClipboardCopyElement) {
      const url = cloneContainer.value
      try {
        await copyText(url)

        // eslint-disable-next-line i18n-text/no-en
        commandPalette.displayFlash('success', 'Branch name copied to clipboard!')
      } catch {
        // eslint-disable-next-line i18n-text/no-en
        commandPalette.displayFlash('error', 'Unable to copy branch name to clipboard!')
      }
    }
  }
}

export default [CopyBranchName, EditPullRequestTitle, EditPullRequestBody, UpdateBranch, ConvertToDraft, OpenCodespace]

import {fetchSafeDocumentFragment} from '@github-ui/fetch-utils'
